-- SEED: 63 Recetas Únicas para MiReto21 AI (21 Desayunos, 21 Almuerzos, 21 Cenas)
-- Idioma: Español | Enfoque: Pérdida de peso saludable (Healthy weight loss)

INSERT INTO public.recipes (id, name, meal_type, image_url, calories, proteins, carbs, fats, prep_time, ingredients, instructions, description, cooking_tips, substitutions, nutritional_benefits, weight_loss_benefits)
VALUES 
--------------------------------------------------------------------------------
-- 21 DESAYUNOS
--------------------------------------------------------------------------------
(gen_random_uuid(), 'Avena clásica con frutos rojos', 'Desayuno', '/images/r_desayuno_1.png', 280, 10, 45, 8, 10, '{"Principal":["1 taza de avena","2 tazas de agua o leche (puede ser vegetal)","1 pizca de sal"],"Opcional":["1/2 taza de frutos rojos (fresas, arándanos, frambuesas)","1 cucharadita de miel o sirope de agave","1 cucharadita de canela en polvo","Nueces o almendras picadas al gusto"]}'::jsonb, '["En una cacerola mediana, lleva a ebullición el agua o la leche con una pizca de sal.","Una vez que el líquido esté hirviendo, agrega la avena y reduce el fuego a medio-bajo.","Cocina la avena a fuego lento durante aproximadamente 5 minutos, removiendo ocasionalmente para evitar que se pegue.","Cuando la avena tenga una consistencia cremosa, retira del fuego y deja reposar durante 1-2 minutos.","Incorpora los frutos rojos, la miel y la canela, mezclando suavemente para combinar los sabores.","Sirve caliente en un bol y espolvorea las nueces o almendras por encima para un extra de crujido y sabor."]'::jsonb, 'Comienza tu día con energía y alegría al disfrutar de esta deliciosa avena clásica con frutos rojos, una combinación perfecta de sabor y nutrición que te hará sentir satisfecho y revitalizado.', '["Para una textura más cremosa, puedes dejar la avena en remojo durante la noche.","Experimenta con diferentes tipos de leche, como la de almendras o coco, para variar el sabor.","Asegúrate de remover la avena mientras se cocina para evitar que se pegue al fondo de la cacerola."]'::jsonb, '["Sustituye la avena tradicional por avena sin gluten si tienes sensibilidad.","Utiliza edulcorantes naturales como el jarabe de arce en lugar de miel si tienes restricciones dietéticas.","Cambia los frutos rojos por otras frutas de temporada como plátano o manzana."]'::jsonb, '["La avena es rica en fibra soluble, lo que ayuda a la digestión y proporciona una sensación de saciedad.","Los frutos rojos son una excelente fuente de antioxidantes, que ayudan a combatir el estrés oxidativo.","Este desayuno es bajo en grasas saturadas y proporciona energía sostenida gracias a sus carbohidratos complejos."]'::jsonb, '["La alta cantidad de fibra en la avena ayuda a controlar el apetito y reducir la ingesta calórica a lo largo del día.","Los frutos rojos son bajos en calorías y altos en nutrientes, lo que los convierte en un snack ideal para perder peso.","Este desayuno equilibrado ayuda a mantener estables los niveles de azúcar en sangre, evitando picos de hambre."]'::jsonb),
(gen_random_uuid(), 'Huevos revueltos con espinacas', 'Desayuno', '/images/r_desayuno_2.png', 250, 18, 5, 15, 10, '{"Principal":["4 huevos grandes","100 g de espinacas frescas","2 cucharadas de leche desnatada","1 cucharada de aceite de oliva","Sal al gusto","Pimienta al gusto"],"Opcional":["Queso feta desmenuzado al gusto","1 diente de ajo picado","Tomate cherry para decorar"]}'::jsonb, '["Lava bien las espinacas frescas y escúrrelas. Si lo deseas, pica un diente de ajo para añadir sabor.","En una sartén antiadherente, calienta el aceite de oliva a fuego medio y añade el ajo picado, salteando hasta que esté dorado.","Agrega las espinacas a la sartén y cocina durante 2-3 minutos, hasta que estén tiernas y reducidas.","En un bol, bate los huevos junto con la leche, la sal y la pimienta hasta que la mezcla esté homogénea.","Vierte la mezcla de huevos sobre las espinacas en la sartén y revuelve suavemente con una espátula, cocinando durante 3-4 minutos hasta que los huevos estén cocidos pero aún cremosos.","Retira del fuego y, si lo deseas, añade queso feta desmenuzado antes de servir. Decora con tomates cherry."]'::jsonb, '¡Empieza tu día con energía! Estos huevos revueltos con espinacas son una deliciosa manera de nutrir tu cuerpo y disfrutar de un desayuno lleno de sabor.', '["Para obtener unos huevos revueltos más cremosos, no los cocines demasiado; deben quedar ligeramente húmedos.","Utiliza una espátula de silicona para evitar dañar la superficie de la sartén y facilitar el movimiento de los huevos.","Si prefieres un sabor más intenso, puedes añadir hierbas frescas como albahaca o cebollino al final de la cocción."]'::jsonb, '["Usa claras de huevo en lugar de huevos enteros para reducir la grasa y calorías.","Sustituye la leche desnatada por leche de almendras o de soja para una opción sin lácteos.","Añade otras verduras como pimientos o champiñones para variar los nutrientes."]'::jsonb, '["Las espinacas son ricas en hierro y antioxidantes, lo que ayuda a mejorar la salud general.","Los huevos son una excelente fuente de proteína de alta calidad, esencial para el desarrollo muscular.","Este platillo es bajo en carbohidratos, lo que lo convierte en una opción ideal para una dieta equilibrada."]'::jsonb, '["Los huevos aumentan la saciedad, lo que puede ayudar a reducir la ingesta calórica a lo largo del día.","Las espinacas son bajas en calorías y altas en fibra, ayudando a mantener la sensación de plenitud.","Este desayuno es fácil de preparar y puede ser una opción rápida y saludable, evitando opciones menos nutritivas."]'::jsonb),
(gen_random_uuid(), 'Tostada de aguacate y huevo', 'Desayuno', '/images/r_desayuno_3.png', 320, 15, 20, 20, 5, '{"Principal":["2 rebanadas de pan integral","1 aguacate maduro","2 huevos","Sal al gusto","Pimienta negra al gusto","1 cucharada de aceite de oliva"],"Opcional":["Rodajas de tomate","Hojitas de cilantro o perejil","Lima o limón exprimido"]}'::jsonb, '["Tuesta las rebanadas de pan integral en una tostadora o sartén hasta que estén doradas y crujientes.","Mientras tanto, corta el aguacate por la mitad, quita el hueso y saca la pulpa con una cuchara.","Aplasta el aguacate en un tazón con un tenedor, agrega sal, pimienta y un chorrito de limón al gusto.","En una sartén, calienta el aceite de oliva a fuego medio y cocina los huevos al gusto: pochados, fritos o revueltos.","Unta generosamente la mezcla de aguacate sobre las tostadas calientes.","Coloca los huevos cocidos sobre la tostada con aguacate y, si deseas, añade rodajas de tomate y cilantro para decorar."]'::jsonb, 'Comienza tu día con esta deliciosa tostada de aguacate y huevo, rica en nutrientes y llena de sabor. Es el desayuno perfecto para energizarte y mantenerte satisfecho hasta el almuerzo.', '["Para un aguacate más cremoso, asegúrate de que esté bien maduro.","Si prefieres un sabor más intenso, añade un toque de chile en polvo o sriracha sobre el aguacate.","Utiliza pan integral para obtener más fibra y nutrientes en tu desayuno."]'::jsonb, '["Pan sin gluten en lugar de pan integral.","Tofu revuelto en lugar de huevo para una opción vegana.","Aguacate en puré con hummus para un sabor diferente."]'::jsonb, '["El aguacate es rico en grasas saludables que ayudan a reducir el colesterol.","Los huevos aportan proteínas de alta calidad, esenciales para la recuperación muscular.","El pan integral es una excelente fuente de fibra, que promueve la salud digestiva."]'::jsonb, '["La combinación de proteínas y grasas saludables ayuda a aumentar la saciedad, reduciendo el apetito durante el día.","Los alimentos ricos en fibra, como el pan integral, contribuyen a un mejor control del peso al promover la saciedad.","El aguacate puede ayudar a regular los niveles de azúcar en sangre, lo que puede evitar antojos y comer en exceso."]'::jsonb),
(gen_random_uuid(), 'Batido verde detox proteico', 'Desayuno', '/images/r_desayuno_4.png', 210, 15, 30, 4, 5, '{"Principal":["1 plátano maduro","1 taza de espinacas frescas","1/2 taza de pepino pelado y picado","1/2 aguacate","1 taza de leche de almendras sin azúcar","1 cucharada de proteína en polvo (opcional)","1 cucharadita de semillas de chía"],"Opcional":["1/2 taza de piña congelada","1 cucharadita de miel o sirope de agave","Unas gotas de limón"]}'::jsonb, '["Lava bien las espinacas y el pepino para eliminar cualquier residuo de tierra o pesticidas.","En una licuadora, agrega el plátano, las espinacas, el pepino y el aguacate.","Vierte la leche de almendras sobre los ingredientes y añade la proteína en polvo si la estás utilizando.","Incorpora las semillas de chía y mezcla todos los ingredientes a alta velocidad hasta obtener una consistencia suave.","Si decides usar piña, miel o limón, agrégalo y mezcla nuevamente para integrar todos los sabores.","Sirve el batido en un vaso grande y disfruta de inmediato para obtener la mejor textura y frescura."]'::jsonb, 'Comienza tu día con energía y frescura con este delicioso batido verde detox, lleno de nutrientes y sabor. Perfecto para revitalizar tu cuerpo y mente desde la primera hora.', '["Utiliza ingredientes frescos y de temporada para maximizar el sabor y los nutrientes.","Congela plátanos maduros para tener una base más cremosa y fría en tu batido.","Prueba diferentes combinaciones de verduras y frutas para variar el sabor y los beneficios nutricionales."]'::jsonb, '["Sustituye la leche de almendras por leche de coco o yogur griego para una textura más cremosa.","Reemplaza el plátano por mango para un sabor más tropical.","Usa kale en lugar de espinacas para un aporte adicional de nutrientes."]'::jsonb, '["Rico en antioxidantes que ayudan a combatir el estrés oxidativo en el cuerpo.","Alto contenido en fibra, lo que favorece la salud digestiva.","Aporta grasas saludables del aguacate que son esenciales para la salud del corazón."]'::jsonb, '["Bajo en calorías pero alto en nutrientes, lo que te ayuda a sentirte saciado sin excederte en calorías.","La fibra en el batido promueve la saciedad y reduce el hambre durante el día.","Las grasas saludables del aguacate ayudan a estabilizar los niveles de azúcar en sangre, lo que puede prevenir antojos."]'::jsonb),
(gen_random_uuid(), 'Yogur griego con nueces', 'Desayuno', '/images/r_desayuno_5.png', 290, 15, 15, 20, 2, '{"Principal":["200g de yogur griego natural","30g de nueces troceadas","1 cucharada de miel","1/2 cucharadita de canela en polvo"],"Opcional":["Frutas frescas como fresas o plátano al gusto","Semillas de chía o linaza"]}'::jsonb, '["En un bol, coloca el yogur griego y asegúrate de que esté bien cremoso.","Añade la miel y la canela al yogur, y mezcla suavemente con una cuchara o batidor hasta que estén bien combinados.","Incorpora las nueces troceadas al yogur y mezcla nuevamente para distribuirlas uniformemente.","Si decides añadir frutas frescas, córtalas en trozos pequeños y agrégalas por encima del yogur.","Decora con un poco más de nueces y espolvorea un poco de canela si lo deseas.","Sirve en un tazón y disfruta de tu nutritivo desayuno inmediatamente."]'::jsonb, 'Disfruta de un comienzo energético con este delicioso yogur griego con nueces, una combinación perfecta de cremosidad y crocancia que hará que tu desayuno sea irresistible.', '["Utiliza yogur griego sin azúcar para controlar la cantidad de azúcares añadidos.","Tuesta ligeramente las nueces en una sartén para realzar su sabor y añadir un toque crujiente.","Experimenta con diferentes frutas de temporada para variar el sabor y los nutrientes."]'::jsonb, '["Sustituye el yogur griego por yogur natural bajo en grasa si prefieres una opción más ligera.","Puedes reemplazar las nueces por almendras o avellanas para un sabor diferente.","Utiliza jarabe de arce en lugar de miel para una opción vegana."]'::jsonb, '["El yogur griego es rico en proteínas, lo que ayuda a mantener la saciedad durante más tiempo.","Las nueces son una excelente fuente de ácidos grasos omega-3, que son beneficiosos para la salud del corazón.","La canela puede ayudar a regular los niveles de azúcar en sangre."]'::jsonb, '["La combinación de proteínas y grasas saludables ayuda a controlar el apetito y reduce la ingesta calórica total.","Los alimentos ricos en fibra, como las nueces y las frutas, contribuyen a una mejor digestión y sensación de saciedad.","El yogur griego puede aumentar el metabolismo debido a su alto contenido proteico."]'::jsonb),
(gen_random_uuid(), 'Pancakes de avena y plátano', 'Desayuno', '/images/r_desayuno_6.png', 310, 12, 45, 8, 15, '{"Principal":["1 taza de avena en hojuelas","1 plátano maduro","2 huevos","1/2 taza de leche (puede ser vegetal)","1 cucharadita de polvo de hornear","1/2 cucharadita de canela en polvo","Una pizca de sal"],"Opcional":["Extracto de vainilla al gusto","Nueces o almendras picadas","Frutas frescas para decorar"]}'::jsonb, '["En un tazón grande, coloca la avena, el polvo de hornear, la canela y la sal. Mezcla bien los ingredientes secos.","En otro tazón, aplasta el plátano con un tenedor hasta que quede puré y luego añade los huevos y la leche. Mezcla hasta que quede homogéneo.","Incorpora la mezcla húmeda a la mezcla de avena y revuelve hasta que todos los ingredientes estén bien integrados.","Calienta una sartén antiadherente a fuego medio y engrásala ligeramente con un poco de aceite o mantequilla.","Vierte una porción de la mezcla en la sartén caliente y cocina durante 2-3 minutos o hasta que aparezcan burbujas en la superficie. Luego, voltea y cocina por 1-2 minutos más.","Repite el proceso con el resto de la mezcla, sirviendo los pancakes calientes y decorando con frutas frescas y nueces si lo deseas."]'::jsonb, 'Disfruta de unos irresistibles pancakes de avena y plátano, perfectos para comenzar el día con energía y sabor. Su textura esponjosa y su dulzura natural te harán querer repetir esta deliciosa receta cada mañana.', '["Deja reposar la mezcla durante unos minutos antes de cocinar para obtener pancakes más esponjosos.","Utiliza una espátula de silicona para voltear los pancakes y evitar que se rompan.","Ajusta la temperatura de la sartén si notas que los pancakes se doran demasiado rápido."]'::jsonb, '["Sustituye los huevos por 1/4 de taza de puré de manzana para una versión vegana.","Cambia la leche por leche de almendra o de avena para una opción sin lactosa.","Utiliza harina de avena en lugar de avena en hojuelas para una textura diferente."]'::jsonb, '["La avena es rica en fibra, lo que ayuda a mantener la sensación de saciedad por más tiempo.","Los plátanos aportan potasio y energía natural, ideales para comenzar el día.","Los huevos son una excelente fuente de proteínas de alta calidad, esenciales para el desarrollo muscular."]'::jsonb, '["Son bajos en calorías, lo que permite disfrutar de un desayuno delicioso sin comprometer tu ingesta calórica.","La combinación de fibra y proteína ayuda a controlar el apetito, reduciendo la probabilidad de picoteo entre comidas.","La avena ayuda a estabilizar los niveles de azúcar en sangre, lo que puede prevenir antojos poco saludables."]'::jsonb),
(gen_random_uuid(), 'Chía pudding con leche de coco', 'Desayuno', '/images/r_desayuno_7.png', 260, 8, 20, 15, 5, '{"Principal":["1/2 taza de semillas de chía","2 tazas de leche de coco","2 cucharadas de miel o sirope de agave","1 cucharadita de extracto de vainilla"],"Opcional":["Frutas frescas (mango, fresas, plátano)","Frutos secos (nueces, almendras)","Coco rallado para decorar"]}'::jsonb, '["En un bol grande, combina las semillas de chía y la leche de coco.","Agrega la miel o sirope de agave y el extracto de vainilla, y mezcla bien hasta que todo esté homogéneo.","Deja reposar la mezcla durante 10 minutos para que las semillas de chía absorban el líquido y se espese.","Revuelve nuevamente para evitar que las semillas se agrupen y asegúrate de que estén bien distribuidas.","Cubre el bol con film transparente y refrigera durante al menos 2 horas, preferiblemente toda la noche.","Antes de servir, mezcla nuevamente y añade tus frutas frescas y frutos secos favoritos como toppings."]'::jsonb, 'Disfruta de un desayuno delicioso y nutritivo con nuestro chía pudding de leche de coco, una explosión de sabores que te llenará de energía para el día.', '["Utiliza leche de coco sin endulzar para controlar la cantidad de azúcar en tu desayuno.","Para una textura más cremosa, puedes batir la leche de coco antes de mezclarla con las semillas de chía.","Prueba a añadir especias como canela o cardamomo para un toque extra de sabor."]'::jsonb, '["Leche de almendra o leche de avena en lugar de leche de coco.","Sirope de arce o azúcar de coco en lugar de miel.","Semillas de linaza en lugar de semillas de chía para variar."]'::jsonb, '["Las semillas de chía son ricas en fibra, lo que promueve la salud digestiva.","La leche de coco proporciona grasas saludables que pueden ayudar a mantener la saciedad.","Este pudding es una fuente de antioxidantes gracias a las frutas frescas que se le pueden añadir."]'::jsonb, '["La fibra de las semillas de chía ayuda a sentirse lleno por más tiempo, reduciendo el hambre.","El consumo de grasas saludables puede mejorar la saciedad y reducir los antojos.","Es un desayuno bajo en calorías que se adapta a dietas equilibradas y controladas."]'::jsonb),
(gen_random_uuid(), 'Tortilla de claras con pavo', 'Desayuno', '/images/r_desayuno_8.png', 200, 25, 5, 8, 10, '{"Principal":["6 claras de huevo","100 g de pechuga de pavo desmenuzada","1 cucharada de aceite de oliva","Sal al gusto","Pimienta al gusto"],"Opcional":["1/4 de taza de espinacas frescas","1/4 de taza de pimientos rojos picados","Queso feta desmenuzado al gusto"]}'::jsonb, '["En un tazón grande, bate las claras de huevo junto con la sal y la pimienta hasta que estén bien mezcladas.","Calienta el aceite de oliva en una sartén antiadherente a fuego medio.","Agrega la pechuga de pavo desmenuzada a la sartén y sofríe durante 2-3 minutos hasta que esté caliente.","Si usas espinacas y pimientos, agrégales a la sartén y cocina por 1-2 minutos más hasta que las espinacas se marchiten.","Vierte las claras de huevo batidas sobre la mezcla de pavo y verduras, asegurándote de que se distribuyan uniformemente.","Cocina a fuego medio-bajo durante 3-4 minutos, o hasta que las claras estén completamente cocidas y la base esté dorada. Voltea con cuidado para cocinar el otro lado si es necesario."]'::jsonb, 'Comienza tu día con energía y sabor con esta deliciosa tortilla de claras con pavo, rica en proteínas y baja en calorías. ¡Una opción perfecta para mantenerte en forma y satisfecho!', '["Utiliza una sartén antiadherente para evitar que la tortilla se pegue y facilitar el volteo.","Bate las claras con un poco de aire para que la tortilla quede más esponjosa.","Si deseas añadir queso, colócalo sobre la tortilla justo antes de doblarla para que se derrita."]'::jsonb, '["Sustituye las claras de huevo por huevos enteros para un perfil nutricional más completo.","Cambia la pechuga de pavo por pollo asado desmenuzado para variar el sabor.","Utiliza aceite de aguacate en lugar de aceite de oliva para un aporte diferente de grasas saludables."]'::jsonb, '["Alto contenido en proteínas, lo que ayuda a mantener la masa muscular.","Bajo en grasas y calorías, ideal para dietas de control de peso.","Rico en vitaminas y minerales si se añaden verduras frescas."]'::jsonb, '["Las claras de huevo son bajas en calorías, lo que permite un desayuno nutritivo sin exceder el requerimiento calórico diario.","Al ser alto en proteínas, promueve la saciedad, ayudando a reducir el picoteo entre comidas.","Incluir pavo magro aumenta la ingesta de proteínas sin añadir grasas excesivas, favoreciendo la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Tazón de queso cottage y fresas', 'Desayuno', '/images/r_desayuno_9.png', 220, 20, 15, 5, 2, '{"Principal":["200g de queso cottage","150g de fresas frescas","1 cucharada de miel","30g de nueces picadas"],"Opcional":["1 cucharadita de semillas de chía","Unas hojas de menta para decorar"]}'::jsonb, '["Lava bien las fresas bajo agua corriente y quítales los tallos.","Corta las fresas en mitades o cuartos, según prefieras.","En un tazón, coloca el queso cottage como base.","Añade las fresas cortadas sobre el queso cottage de manera uniforme.","Rocía la miel sobre las fresas y el queso cottage para dar un toque dulce.","Decora con las nueces picadas y, si lo deseas, añade las semillas de chía y las hojas de menta."]'::jsonb, 'Comienza tu día con un tazón de queso cottage y fresas que no solo es delicioso, sino también nutritivo. Disfruta de la frescura de las fresas combinadas con la cremosidad del queso cottage para un desayuno perfecto.', '["Utiliza fresas orgánicas para un sabor más intenso y menos pesticidas.","Deja el queso cottage a temperatura ambiente durante unos minutos antes de servir para que tenga una consistencia más suave.","Prueba tostar las nueces ligeramente para potenciar su sabor."]'::jsonb, '["Sustituye el queso cottage por yogur griego para una opción más cremosa.","Cambia las fresas por arándanos o plátano para variar los sabores.","Usa sirope de agave en lugar de miel para una opción vegana."]'::jsonb, '["El queso cottage es rico en proteínas, lo que ayuda a mantener la saciedad.","Las fresas son una excelente fuente de antioxidantes y vitamina C.","Las nueces aportan ácidos grasos saludables y fibra."]'::jsonb, '["Bajo en calorías, lo que permite disfrutar de un desayuno satisfactorio sin excederse.","Las proteínas del queso cottage ayudan a reducir el hambre a lo largo del día.","La fibra de las fresas y nueces promueve una digestión saludable y puede ayudar a controlar el peso."]'::jsonb),
(gen_random_uuid(), 'Tostada integral con crema de cacahuete', 'Desayuno', '/images/r_desayuno_10.png', 300, 10, 30, 15, 5, '{"Principal":["2 rebanadas de pan integral","2 cucharadas de crema de cacahuete natural","1 plátano en rodajas"],"Opcional":["1 cucharadita de miel","Canela al gusto","Semillas de chía para decorar"]}'::jsonb, '["Tuesta las rebanadas de pan integral en una tostadora o en una sartén hasta que estén doradas y crujientes.","Mientras se tuestan, corta el plátano en rodajas finas.","Una vez que el pan esté listo, unta generosamente la crema de cacahuete sobre cada rebanada.","Coloca las rodajas de plátano sobre la crema de cacahuete de manera uniforme.","Si lo deseas, añade un chorrito de miel y espolvorea canela al gusto sobre las tostadas.","Decora con semillas de chía para un extra de nutrientes y sirve inmediatamente."]'::jsonb, 'Disfruta de una deliciosa tostada integral con crema de cacahuete, perfecta para comenzar el día con energía y satisfacción. Cada bocado es un deleite que nutre tu cuerpo y alma.', '["Utiliza crema de cacahuete sin azúcar añadida para una opción más saludable.","Ajusta la cantidad de crema de cacahuete según tu preferencia, pero recuerda que un poco puede ser suficiente para disfrutar del sabor sin exceder las calorías.","Experimenta con diferentes frutas como fresas o manzanas para variar el sabor de tus tostadas."]'::jsonb, '["Sustituye la crema de cacahuete por crema de almendra para un sabor diferente.","Cambia el pan integral por pan de centeno o pan sin gluten según tus necesidades dietéticas.","Utiliza aguacate en lugar de plátano para una opción más cremosa y rica en grasas saludables."]'::jsonb, '["La crema de cacahuete es rica en proteínas y grasas saludables, que ayudan a mantener la saciedad.","El plátano aporta potasio y fibra, contribuyendo a una buena digestión.","El pan integral proporciona carbohidratos complejos, que son una fuente de energía sostenida."]'::jsonb, '["Al ser alto en proteínas y fibra, este desayuno ayuda a controlar el apetito durante el día.","Las grasas saludables de la crema de cacahuete pueden ayudar a reducir los antojos, evitando picoteos innecesarios.","El consumo de carbohidratos complejos en el pan integral promueve una liberación de energía más estable, evitando picos de insulina."]'::jsonb),
(gen_random_uuid(), 'Huevos duros con tomates cherry', 'Desayuno', '/images/r_desayuno_11.png', 240, 14, 10, 14, 12, '{"Principal":["4 huevos grandes","200 g de tomates cherry","1 cucharada de aceite de oliva","Sal al gusto","Pimienta negra al gusto"],"Opcional":["Albahaca fresca para decorar","Queso feta desmenuzado (50 g)","Semillas de chía (1 cucharadita)"]}'::jsonb, '["Llenar una olla con agua suficiente para cubrir los huevos y llevar a ebullición a fuego medio-alto.","Una vez que el agua esté hirviendo, añadir suavemente los huevos y cocinar durante 9-12 minutos según el punto de cocción deseado.","Mientras los huevos se cocinan, lavar los tomates cherry y cortarlos por la mitad.","En un tazón, mezclar los tomates cherry con el aceite de oliva, sal y pimienta al gusto.","Al finalizar la cocción, retirar los huevos del agua caliente y sumergirlos en un recipiente con agua fría para detener la cocción.","Pelar los huevos una vez que estén fríos y servirlos cortados por la mitad junto con los tomates cherry sazonados."]'::jsonb, 'Comienza tu día con energía y colorido con estos huevos duros acompañados de frescos tomates cherry. Una combinación deliciosa y nutritiva que te hará sentir bien desde la primera mordida.', '["Para huevos más fáciles de pelar, utiliza huevos que tengan unos días de antigüedad en lugar de frescos.","Asegúrate de no cocinar los huevos en exceso para evitar que la yema se ponga verde.","Puedes usar un temporizador para controlar el tiempo de cocción y conseguir el punto perfecto de los huevos."]'::jsonb, '["En lugar de aceite de oliva, puedes usar aceite de aguacate para un sabor diferente.","Si no tienes tomates cherry, puedes usar tomates cortados en cubos.","Sustituye el queso feta por aguacate para una opción más cremosa y saludable."]'::jsonb, '["Los huevos son una excelente fuente de proteínas de alta calidad, fundamentales para el crecimiento y la reparación muscular.","Los tomates cherry son ricos en antioxidantes, que ayudan a combatir el daño celular.","Esta combinación es baja en carbohidratos y alta en nutrientes, ideal para una alimentación balanceada."]'::jsonb, '["La proteína en los huevos ayuda a aumentar la saciedad, lo que puede reducir el apetito y la ingesta calórica total.","Los tomates cherry son bajos en calorías y contienen fibra, lo que favorece la digestión y la sensación de plenitud.","Esta receta es rica en nutrientes que pueden ayudar a mantener la energía durante el día, evitando el picoteo innecesario."]'::jsonb),
(gen_random_uuid(), 'Avena horneada con manzana', 'Desayuno', '/images/r_desayuno_12.png', 330, 8, 50, 10, 25, '{"Principal":["2 tazas de avena","2 tazas de leche (puede ser vegetal)","2 manzanas medianas, peladas y picadas","1/2 taza de miel o sirope de arce","1 cucharadita de canela","1/2 cucharadita de nuez moscada","1/4 taza de nueces picadas","1/4 cucharadita de sal","2 huevos"],"Opcional":["1/2 taza de pasas","1 cucharadita de extracto de vainilla","Frutas frescas para decorar"]}'::jsonb, '["Precalienta el horno a 180°C (350°F) y engrasa ligeramente un molde para hornear.","En un tazón grande, mezcla la avena, la leche, las manzanas, la miel, la canela, la nuez moscada, las nueces y la sal.","En otro tazón, bate los huevos y agrégales a la mezcla de avena, asegurándote de que todo esté bien combinado.","Vierte la mezcla en el molde preparado y distribúyela uniformemente.","Hornea durante 30-35 minutos, o hasta que la parte superior esté dorada y la mezcla esté firme al tacto.","Deja enfriar durante unos minutos antes de cortar y servir. Puedes añadir frutas frescas por encima si lo deseas."]'::jsonb, 'Comienza tu día con esta deliciosa avena horneada con manzana, una combinación perfecta de dulzura natural y nutrición que te llenará de energía y satisfacción.', '["Para una textura más cremosa, puedes remojar la avena en la leche durante la noche antes de hornear.","Experimenta con diferentes frutas de temporada para variar el sabor de la receta.","Asegúrate de no sobrecocinar, ya que la avena puede volverse seca."]'::jsonb, '["Sustituye la miel por puré de plátano para una opción más baja en azúcar.","Utiliza yogur griego en lugar de leche para un aporte extra de proteínas.","Cambia las nueces por almendras o semillas de chía para diversificar los nutrientes."]'::jsonb, '["La avena es rica en fibra soluble, lo que ayuda a reducir el colesterol y mejorar la salud digestiva.","Las manzanas aportan antioxidantes y vitamina C, lo que contribuye a fortalecer el sistema inmunológico.","Las nueces son una excelente fuente de grasas saludables, que benefician la salud del corazón."]'::jsonb, '["La alta cantidad de fibra en la avena y las manzanas promueve la saciedad, ayudando a controlar el apetito.","Los ingredientes naturales y sin procesar son bajos en calorías, lo que facilita la pérdida de peso.","Esta receta proporciona energía sostenida, evitando picos de azúcar en la sangre que pueden llevar a antojos."]'::jsonb),
(gen_random_uuid(), 'Batido de frutos rojos y espinaca', 'Desayuno', '/images/r_desayuno_13.png', 190, 5, 35, 2, 5, '{"Principal":["1 taza de espinaca fresca","1/2 taza de fresas congeladas","1/2 taza de arándanos congelados","1 plátano maduro","1 taza de leche de almendras sin azúcar","1 cucharada de semillas de chía"],"Opcional":["1 cucharadita de miel o sirope de agave","1/2 cucharadita de canela en polvo","Un puñado de nueces para topping"]}'::jsonb, '["Lava bien la espinaca fresca y escúrrela para eliminar el exceso de agua.","En una licuadora, agrega la espinaca, las fresas, los arándanos y el plátano pelado.","Vierte la leche de almendras en la licuadora junto con las semillas de chía.","Licúa todos los ingredientes a alta velocidad hasta que obtengas una mezcla suave y homogénea.","Si deseas un batido más dulce, añade miel o sirope de agave y mezcla nuevamente.","Sirve el batido en un vaso grande y, si lo deseas, espolvorea canela y agrega nueces por encima como topping."]'::jsonb, 'Comienza tu día con energía y vitalidad con este delicioso batido de frutos rojos y espinaca, lleno de antioxidantes y nutrientes esenciales que te harán sentir increíble.', '["Utiliza frutas congeladas para un batido más espeso y refrescante.","Puedes preparar la mezcla de ingredientes secos con antelación y guardarla en la nevera para un desayuno rápido.","Asegúrate de que las espinacas estén frescas para obtener el mejor sabor y nutrientes."]'::jsonb, '["Sustituye la leche de almendras por leche de coco o yogur griego para una textura más cremosa.","Puedes usar espinaca congelada en lugar de fresca si no tienes acceso a la fresca.","Reemplaza las frutas por otras de tu elección, como mango o piña, para variar el sabor."]'::jsonb, '["Las espinacas son ricas en hierro y vitaminas A, C y K, esenciales para la salud ocular y la función inmunológica.","Los frutos rojos son altos en antioxidantes, que ayudan a combatir el estrés oxidativo en el cuerpo.","Las semillas de chía son una excelente fuente de ácidos grasos omega-3 y fibra, que promueven la salud digestiva."]'::jsonb, '["Este batido es bajo en calorías pero alto en nutrientes, lo que ayuda a mantener la saciedad sin exceder el consumo calórico.","La fibra de las frutas y las semillas de chía ayuda a regular el apetito y reduce los antojos.","Las espinacas son bajas en calorías y altas en agua, lo que contribuye a la sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Omelette de champiñones', 'Desayuno', '/images/r_desayuno_14.png', 250, 16, 5, 18, 10, '{"Principal":["3 huevos grandes","100 g de champiñones frescos, laminados","1 cucharada de aceite de oliva","Sal al gusto","Pimienta negra al gusto"],"Opcional":["30 g de queso feta desmenuzado","Un puñado de espinacas frescas","Cebollín picado para decorar"]}'::jsonb, '["En una sartén antiadherente, calienta el aceite de oliva a fuego medio.","Agrega los champiñones laminados y saltea durante 5 minutos hasta que estén dorados y tiernos.","Mientras tanto, en un bol, bate los huevos con sal y pimienta hasta que estén bien mezclados.","Vierte los huevos batidos sobre los champiñones en la sartén, asegurándote de que se distribuyan uniformemente.","Cocina a fuego medio-bajo durante unos 4-5 minutos, o hasta que los bordes comiencen a cuajar.","Si lo deseas, añade el queso feta y las espinacas en la parte superior, luego dobla el omelette por la mitad y cocina por un minuto adicional antes de servir."]'::jsonb, 'Disfruta de un delicioso omelette de champiñones que no solo es sabroso, sino que también llena de energía tu mañana. Perfecto para comenzar el día con una dosis de proteínas y nutrientes esenciales.', '["Utiliza huevos frescos para obtener un sabor más rico y una mejor textura.","No sobrecocines el omelette; debe quedar ligeramente cremoso por dentro.","Experimenta con diferentes hierbas frescas como el perejil o el orégano para realzar el sabor."]'::jsonb, '["Sustituye los huevos por claras de huevo para una opción más baja en calorías.","Utiliza champiñones shiitake o portobello para un sabor más intenso.","Reemplaza el aceite de oliva por aceite de aguacate para un perfil de sabor diferente."]'::jsonb, '["Los champiñones son una excelente fuente de antioxidantes y vitaminas del grupo B.","Los huevos son ricos en proteínas de alta calidad, esenciales para el desarrollo muscular.","Este plato es bajo en carbohidratos, lo que lo hace ideal para dietas cetogénicas."]'::jsonb, '["Al ser rico en proteínas, ayuda a mantener la saciedad durante más tiempo.","Es bajo en calorías, lo que permite un control más fácil de la ingesta calórica diaria.","Los ingredientes saludables promueven una digestión eficiente, apoyando la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Muffins de huevo y verduras', 'Desayuno', '/images/r_desayuno_15.png', 210, 18, 5, 12, 20, '{"Principal":["6 huevos grandes","1 taza de espinacas frescas picadas","1/2 taza de pimientos rojos picados","1/2 taza de cebolla picada","1/2 taza de queso feta desmenuzado","1/4 taza de leche","Sal y pimienta al gusto"],"Opcional":["1/4 taza de champiñones picados","1 cucharada de hierbas frescas (perejil, albahaca o eneldo)","Pimienta roja al gusto"]}'::jsonb, '["Precalienta el horno a 180°C (350°F) y engrasa un molde para muffins con aceite en spray o mantequilla.","En un tazón grande, bate los huevos junto con la leche, la sal y la pimienta hasta que estén bien combinados.","Agrega las espinacas, los pimientos, la cebolla y, si deseas, los champiñones y hierbas frescas al tazón con los huevos batidos. Mezcla todo hasta que las verduras estén bien distribuidas.","Vierte la mezcla de huevo y verduras en los moldes para muffins, llenándolos hasta 3/4 de su capacidad.","Espolvorea el queso feta desmenuzado sobre la mezcla en cada muffin.","Hornea durante 20-25 minutos o hasta que los muffins estén firmes y dorados en la parte superior. Deja enfriar un poco antes de desmoldar."]'::jsonb, 'Disfruta de unos deliciosos muffins de huevo y verduras, perfectos para comenzar el día con energía y sabor. Esta receta es una forma saludable y divertida de incorporar verduras en tu desayuno.', '["Puedes añadir una pizca de cúrcuma en la mezcla de huevo para un color vibrante y beneficios antiinflamatorios.","Asegúrate de no sobrecocer los muffins, ya que podrían volverse secos; deben estar firmes al tacto.","Experimenta con diferentes combinaciones de verduras según la temporada para mantener la receta fresca y emocionante."]'::jsonb, '["Sustituye el queso feta por queso ricotta o queso cottage para una opción más ligera.","Usa claras de huevo en lugar de huevos enteros para reducir la grasa y las calorías.","Cambia las espinacas por kale o acelgas para variar los nutrientes."]'::jsonb, '["Ricos en proteínas gracias a los huevos, lo que ayuda a la construcción muscular y a la saciedad.","Las verduras aportan fibra, vitaminas y minerales esenciales para una dieta equilibrada.","El queso feta proporciona calcio, importante para la salud ósea."]'::jsonb, '["Bajos en carbohidratos, lo que ayuda a mantener estables los niveles de azúcar en sangre y reduce los antojos.","Ricos en proteínas que promueven la sensación de saciedad y reducen la ingesta calórica total.","Las verduras añaden volumen a la comida sin muchas calorías, lo que ayuda a controlar el peso."]'::jsonb),
(gen_random_uuid(), 'Porridge de avena y cacao', 'Desayuno', '/images/r_desayuno_16.png', 290, 10, 45, 8, 10, '{"Principal":["1 taza de avena","2 tazas de agua o leche (puede ser vegetal)","2 cucharadas de cacao en polvo sin azúcar","1 cucharada de miel o sirope de agave","1/2 plátano en rodajas","1/4 de taza de nueces o almendras picadas"],"Opcional":["Canela al gusto","Frutas frescas (fresas, arándanos)","Semillas de chía o linaza"]}'::jsonb, '["En una cacerola, lleva el agua o la leche a ebullición a fuego medio.","Agrega la avena y el cacao en polvo, mezclando bien para evitar grumos.","Reduce el fuego a bajo y cocina a fuego lento, removiendo ocasionalmente, durante unos 5-7 minutos o hasta que la avena esté suave y cremosa.","Retira del fuego y añade la miel o sirope de agave, mezclando bien para incorporar.","Sirve el porridge en un tazón y decora con las rodajas de plátano y las nueces o almendras picadas.","Si lo deseas, agrega canela y tus frutas frescas favoritas para un extra de sabor y nutrientes."]'::jsonb, 'Disfruta de un delicioso Porridge de avena y cacao que no solo satisface tu paladar, sino que también te llena de energía para comenzar el día con fuerza.', '["Para un porridge más cremoso, utiliza leche en lugar de agua y cocina a fuego lento durante unos minutos más.","Prueba a tostar ligeramente las nueces o almendras antes de añadirlas; esto realza su sabor.","Si prefieres una textura más suave, puedes triturar la avena antes de cocinarla."]'::jsonb, '["Utiliza avena instantánea si tienes poco tiempo, aunque la avena tradicional es más nutritiva.","Sustituye la miel por un edulcorante natural como el sirope de arce.","Cambia el cacao por polvo de algarrobo para una opción más dulce y baja en cafeína."]'::jsonb, '["La avena es rica en fibra soluble, lo que ayuda a mantener niveles estables de azúcar en sangre.","El cacao proporciona antioxidantes que pueden mejorar la salud cardiovascular.","Las nueces son una excelente fuente de grasas saludables, proteínas y micronutrientes."]'::jsonb, '["La fibra de la avena ayuda a sentir saciedad por más tiempo, reduciendo el apetito.","El bajo índice glucémico de este desayuno ayuda a evitar picos de insulina, favoreciendo la pérdida de peso.","El cacao puede ayudar a reducir el deseo de comer algo dulce, lo que puede ser beneficioso para controlar las calorías."]'::jsonb),
(gen_random_uuid(), 'Tostada con hummus y tomate', 'Desayuno', '/images/r_desayuno_17.png', 280, 8, 35, 10, 5, '{"Principal":["2 rebanadas de pan integral","100 g de hummus","1 tomate grande, en rodajas","1 cucharada de aceite de oliva virgen extra","Sal y pimienta al gusto"],"Opcional":["Hojas de albahaca fresca","Semillas de sésamo tostadas","Pimienta roja o pimentón para decorar"]}'::jsonb, '["Tuesta las rebanadas de pan integral en una tostadora o en una sartén hasta que estén doradas y crujientes.","Mientras el pan se tuesta, corta el tomate en rodajas finas y resérvalas.","Una vez que el pan esté listo, unta generosamente el hummus sobre cada rebanada.","Coloca las rodajas de tomate sobre el hummus, asegurándote de cubrir bien la superficie.","Rocía con aceite de oliva virgen extra y sazona con sal y pimienta al gusto.","Si lo deseas, añade las hojas de albahaca y las semillas de sésamo tostadas como guarnición antes de servir."]'::jsonb, 'Comienza tu día con una explosión de sabor y energía. Esta tostada con hummus y tomate es el desayuno perfecto para nutrir tu cuerpo y deleitar tu paladar.', '["Asegúrate de elegir un pan integral de buena calidad para obtener más fibra y nutrientes.","Puedes hacer tu propio hummus en casa utilizando garbanzos cocidos, tahini, ajo y limón para un sabor más fresco.","No dudes en experimentar con diferentes tipos de tomates, como los cherry o los heirloom, para variar los sabores."]'::jsonb, '["Pan sin gluten en lugar de pan integral.","Hummus de remolacha o pimiento asado para un sabor diferente.","Aguacate en lugar de hummus para una opción cremosa y saludable."]'::jsonb, '["El hummus es rico en proteínas y fibra, lo que ayuda a mantener la saciedad por más tiempo.","Los tomates son una excelente fuente de antioxidantes, como el licopeno, que promueve la salud cardiovascular.","El aceite de oliva virgen extra contiene grasas saludables que benefician el corazón y ayudan a reducir la inflamación."]'::jsonb, '["Al ser rico en proteínas y fibra, el hummus ayuda a controlar el apetito y reduce los antojos.","El pan integral proporciona carbohidratos complejos que liberan energía de forma sostenida, evitando picos de azúcar en sangre.","Las grasas saludables del aguacate o del aceite de oliva pueden aumentar la sensación de saciedad, lo que puede ayudar a reducir la ingesta calórica total."]'::jsonb),
(gen_random_uuid(), 'Wrap integral de pavo y lechuga', 'Desayuno', '/images/r_desayuno_18.png', 310, 20, 30, 10, 5, '{"Principal":["1 tortilla integral","100 g de pechuga de pavo en lonchas","1 hoja grande de lechuga romana","1/4 de aguacate","1 cucharada de mostaza","1 rodaja de tomate"],"Opcional":["Queso bajo en grasa al gusto","Pepinillos en rodajas","Semillas de chía para espolvorear"]}'::jsonb, '["Lava bien la hoja de lechuga y sécala con cuidado para que no quede humedad.","En una superficie plana, coloca la tortilla integral y unta la mostaza en toda su superficie.","Coloca las lonchas de pavo uniformemente sobre la tortilla, dejando un borde en los lados.","Agrega la hoja de lechuga, la rodaja de tomate y el aguacate en rodajas en el centro de la tortilla.","Si deseas, añade queso bajo en grasa o pepinillos para un extra de sabor.","Enrolla la tortilla desde el borde más cercano a ti, asegurándote de envolver bien todos los ingredientes y formando un cilindro.","Corta el wrap por la mitad y sírvelo inmediatamente o envuélvelo para llevar."]'::jsonb, 'Disfruta de un delicioso wrap integral de pavo y lechuga que combina frescura y proteínas magras, ideal para comenzar el día con energía y sabor.', '["Utiliza tortillas integrales frescas para obtener la mejor textura y sabor.","Puedes calentar ligeramente la tortilla en una sartén antes de agregar los ingredientes para que sea más flexible.","Asegúrate de no sobrecargar el wrap para que puedas enrollarlo fácilmente sin que se rompa."]'::jsonb, '["Sustituye la pechuga de pavo por pollo a la parrilla o tofu para una opción vegetariana.","Cambia la mostaza por hummus o guacamole para un sabor diferente.","Utiliza espinacas en lugar de lechuga para un extra de nutrientes."]'::jsonb, '["El pavo es una excelente fuente de proteínas magras, ideal para el desarrollo muscular.","La lechuga y el aguacate aportan fibra y grasas saludables, que son esenciales para una dieta equilibrada.","Las tortillas integrales ofrecen carbohidratos complejos, que proporcionan energía sostenida."]'::jsonb, '["Bajo en calorías y alto en proteínas, lo que ayuda a mantener la saciedad por más tiempo.","Al estar cargado de vegetales, ayuda a aumentar la ingesta de fibra, lo que facilita la digestión.","Las grasas saludables del aguacate pueden ayudar a controlar el apetito y reducir el deseo de comer en exceso."]'::jsonb),
(gen_random_uuid(), 'Smoothie bowl de mango', 'Desayuno', '/images/r_desayuno_19.png', 260, 5, 50, 4, 5, '{"Principal":["1 mango maduro, pelado y picado","1 banana, congelada","1/2 taza de yogur griego natural","1/2 taza de leche de almendra sin azúcar","1 cucharada de semillas de chía"],"Opcional":["Rodajas de kiwi para decorar","Frutos rojos (fresas, arándanos) para decorar","Coco rallado al gusto"]}'::jsonb, '["En una licuadora, combina el mango picado, la banana congelada, el yogur griego y la leche de almendra.","Añade las semillas de chía a la mezcla y licúa a alta velocidad hasta obtener una textura suave y cremosa.","Si la mezcla es demasiado espesa, añade un poco más de leche de almendra para alcanzar la consistencia deseada.","Vierte la mezcla en un tazón grande y alisa la superficie con una cuchara.","Decora la parte superior con rodajas de kiwi, frutos rojos y coco rallado al gusto.","Disfruta tu smoothie bowl inmediatamente para aprovechar su frescura y nutrientes."]'::jsonb, 'Disfruta de un delicioso smoothie bowl de mango que no solo es un festín para tus papilas, sino también una explosión de energía y frescura para comenzar el día con buen pie.', '["Asegúrate de que el mango esté bien maduro para obtener el mejor sabor y dulzura.","Utiliza frutas congeladas para una textura más cremosa y un smoothie más refrescante.","Experimenta con diferentes toppings como nueces o semillas para añadir textura y nutrientes."]'::jsonb, '["Puedes sustituir el yogur griego por yogur de coco para una opción vegana.","Reemplaza la leche de almendra por leche de avena o de soya si prefieres otro tipo de leche.","Si no tienes mango, puedes usar piña o durazno como alternativa."]'::jsonb, '["El mango es rico en vitamina C, que fortalece el sistema inmunológico.","Las semillas de chía son una excelente fuente de ácidos grasos omega-3 y fibra.","El yogur griego aporta probióticos que favorecen la salud digestiva."]'::jsonb, '["La fibra de las frutas y las semillas ayuda a mantener la saciedad durante más tiempo.","Las proteínas del yogur griego contribuyen a la conservación de la masa muscular mientras se pierde peso.","Este smoothie bowl es bajo en calorías y alto en nutrientes, lo que lo convierte en una excelente opción para un desayuno equilibrado."]'::jsonb),
(gen_random_uuid(), 'Huevos revueltos con tomate y albahaca', 'Desayuno', '/images/r_desayuno_20.png', 230, 14, 5, 16, 8, '{"Principal":["4 huevos","1 tomate grande, picado","1 cucharada de albahaca fresca, picada","1 cucharada de aceite de oliva","Sal y pimienta al gusto"],"Opcional":["Queso feta desmenuzado al gusto","Pan integral para acompañar"]}'::jsonb, '["En un bol, bate los huevos con una pizca de sal y pimienta hasta que estén bien mezclados.","Calienta el aceite de oliva en una sartén antiadherente a fuego medio.","Agrega el tomate picado a la sartén y cocina durante 2-3 minutos, hasta que se ablande y suelte sus jugos.","Reduce el fuego a bajo y vierte los huevos batidos en la sartén con el tomate.","Con una espátula, revuelve suavemente los huevos mientras se cocinan, asegurándote de que no se cocinen demasiado.","Cuando los huevos estén casi listos, añade la albahaca fresca y mezcla bien antes de servir."]'::jsonb, 'Disfruta de unos huevos revueltos cremosos y llenos de sabor, combinados con tomate fresco y albahaca aromática. Este desayuno no solo es delicioso, sino también nutritivo y lleno de energía para comenzar tu día.', '["Utiliza huevos frescos para obtener la mejor textura y sabor.","No sobrecocines los huevos; deben quedar cremosos y ligeramente húmedos.","Experimenta añadiendo otros vegetales como espinacas o champiñones para variar el sabor."]'::jsonb, '["Usa claras de huevo en lugar de huevos enteros para reducir las calorías.","Sustituye el aceite de oliva por spray de aceite para una opción más ligera.","Reemplaza el tomate fresco por tomate seco si prefieres un sabor más intenso."]'::jsonb, '["Los huevos son una excelente fuente de proteínas de alta calidad, esenciales para el desarrollo muscular.","El tomate aporta licopeno, un antioxidante que puede ayudar a reducir el riesgo de enfermedades cardíacas.","La albahaca tiene propiedades antiinflamatorias y es rica en vitaminas A y K."]'::jsonb, '["Los huevos ayudan a aumentar la saciedad, lo que puede reducir el consumo total de calorías durante el día.","Las proteínas en los huevos pueden acelerar el metabolismo, ayudando en la quema de grasa.","El bajo contenido calórico de este desayuno lo convierte en una opción ideal para quienes buscan perder peso."]'::jsonb),
(gen_random_uuid(), 'Kéfir con trozos de fruta', 'Desayuno', '/images/r_desayuno_21.png', 210, 10, 30, 5, 2, '{"Principal":["200 ml de kéfir","1 plátano maduro, en rodajas","1/2 taza de fresas, en trozos","1/2 taza de arándanos","1 cucharada de miel (opcional)"],"Opcional":["1 cucharada de semillas de chía","Nueces picadas al gusto","Canela al gusto"]}'::jsonb, '["En un bol grande, vierte el kéfir y asegúrate de que esté bien mezclado.","Agrega las rodajas de plátano al kéfir y mezcla suavemente para que no se deshagan.","Incorpora las fresas y los arándanos, asegurándote de distribuirlas uniformemente.","Si lo deseas, añade una cucharada de miel para darle un toque dulce.","Si optas por hacerlo más nutritivo, agrega las semillas de chía y las nueces picadas.","Espolvorea un poco de canela por encima para un sabor extra y disfruta de tu desayuno."]'::jsonb, 'Disfruta de un desayuno fresco y lleno de energía con nuestro delicioso Kéfir con trozos de fruta, una opción perfecta para empezar el día con vitalidad y sabor.', '["Utiliza fruta fresca de temporada para obtener el mejor sabor y nutrientes.","Deja que el kéfir alcance la temperatura ambiente antes de servir para una textura más suave.","Experimenta con diferentes combinaciones de frutas para mantener tu desayuno interesante."]'::jsonb, '["Puedes sustituir el kéfir por yogur natural o yogur griego.","Cambia las fresas y arándanos por cualquier otra fruta de tu preferencia, como kiwi o mango.","Sustituye la miel por sirope de agave o edulcorantes naturales si buscas reducir calorías."]'::jsonb, '["El kéfir es una excelente fuente de probióticos, que favorecen la salud digestiva.","Las frutas aportan vitaminas, minerales y antioxidantes esenciales para el cuerpo.","Las semillas de chía son ricas en fibra, lo que ayuda a mantener la saciedad."]'::jsonb, '["El kéfir puede ayudar a regular el apetito y disminuir la ingesta calórica total.","Las frutas son bajas en calorías y altas en fibra, lo que contribuye a la pérdida de peso.","La combinación de proteínas y fibra en este desayuno ayuda a mantener la saciedad por más tiempo."]'::jsonb),

--------------------------------------------------------------------------------
-- 21 ALMUERZOS
--------------------------------------------------------------------------------
(gen_random_uuid(), 'Pollo a la plancha con quinoa', 'Almuerzo', '/images/r_almuerzo_1.png', 420, 40, 45, 12, 20, '{"Principal":["2 pechugas de pollo (aproximadamente 200 g cada una)","1 taza de quinoa","2 tazas de agua o caldo de pollo","1 cucharada de aceite de oliva","Sal y pimienta al gusto"],"Opcional":["1 cucharadita de pimentón dulce","1 cucharada de jugo de limón","Verduras al gusto (espinacas, pimientos, brócoli)"]}'::jsonb, '["Lava la quinoa bajo agua fría para remover el amargor y colócala en una olla con 2 tazas de agua o caldo de pollo.","Agrega una pizca de sal y lleva a ebullición. Reduce el fuego y cocina a fuego lento durante 15 minutos o hasta que el agua se haya absorbido.","Mientras tanto, sazona las pechugas de pollo con sal, pimienta y pimentón dulce si lo deseas.","Calienta una sartén a fuego medio-alto y añade el aceite de oliva.","Coloca las pechugas de pollo en la sartén y cocina durante 6-7 minutos por cada lado, o hasta que estén doradas y completamente cocidas.","Una vez la quinoa esté lista, esponja con un tenedor y mezcla con el jugo de limón y las verduras opcionales antes de servir."]'::jsonb, 'Disfruta de un delicioso pollo a la plancha con quinoa, una combinación perfecta de proteínas magras y granos saludables que te llenará de energía y bienestar.', '["Deja reposar el pollo durante unos minutos después de cocinarlo para que retenga su jugo.","Si deseas un toque extra de sabor, marinar el pollo en una mezcla de aceite de oliva, limón y hierbas frescas por al menos 30 minutos antes de cocinar.","Asegúrate de no sobrecocinar la quinoa; debe estar tierna pero con un ligero crujido."]'::jsonb, '["Pechuga de pollo por pechuga de pavo.","Quinoa por arroz integral o cuscús.","Aceite de oliva por aceite de aguacate."]'::jsonb, '["El pollo es una excelente fuente de proteínas magras que ayudan a mantener la masa muscular.","La quinoa es un grano completo que proporciona todos los aminoácidos esenciales y es rica en fibra.","Las verduras agregadas aportan vitaminas y minerales esenciales, aumentando el valor nutricional del plato."]'::jsonb, '["La alta cantidad de proteínas en el pollo ayuda a aumentar la saciedad y reducir el hambre.","La quinoa es rica en fibra, lo que promueve una digestión saludable y ayuda a mantenerte satisfecho por más tiempo.","El bajo contenido calórico de este plato en comparación con opciones más pesadas facilita la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Ensalada de Atún y aguacate', 'Almuerzo', '/images/r_almuerzo_2.png', 380, 30, 15, 22, 10, '{"Principal":["1 lata de atún en agua (aproximadamente 150g)","1 aguacate maduro","2 tazas de espinacas frescas","1/2 taza de tomate cherry","1/4 de cebolla morada","1 cucharada de aceite de oliva","1 cucharada de jugo de limón","Sal y pimienta al gusto"],"Opcional":["1/4 de taza de maíz dulce","1/4 de taza de aceitunas negras","1 cucharada de semillas de chía"]}'::jsonb, '["Escurre el atún y colócalo en un tazón grande.","Corta el aguacate por la mitad, quita el hueso y saca la pulpa con una cuchara. Corta el aguacate en cubos y agrégalo al tazón con el atún.","Lava las espinacas y colócalas en el fondo de un plato grande o ensaladera.","Corta los tomates cherry por la mitad y la cebolla morada en rodajas finas. Agréguelos al tazón con el atún y aguacate.","En un pequeño tazón, mezcla el aceite de oliva, el jugo de limón, la sal y la pimienta. Revuelve bien para emulsionar.","Vierte el aderezo sobre la ensalada y mezcla suavemente para combinar todos los ingredientes sin aplastar el aguacate."]'::jsonb, 'Disfruta de esta fresca y deliciosa ensalada de atún y aguacate, rica en nutrientes y perfecta para mantenerte enérgico durante todo el día.', '["Utiliza atún en agua para una opción más ligera y baja en calorías.","Asegúrate de que el aguacate esté maduro para obtener la mejor textura y sabor.","Puedes añadir hierbas frescas como cilantro o perejil para un toque extra de frescura."]'::jsonb, '["Sustituye el atún por pollo a la parrilla para una opción diferente.","Usa yogur griego en lugar de aceite de oliva para un aderezo más cremoso y bajo en grasa.","Cambia las espinacas por rúcula para un sabor más picante."]'::jsonb, '["El aguacate es rico en grasas saludables que ayudan a mantener el corazón sano.","El atún es una excelente fuente de proteínas magras, ideal para el desarrollo muscular.","Las espinacas aportan una gran cantidad de vitaminas y minerales esenciales, como hierro y vitamina K."]'::jsonb, '["La combinación de proteínas y grasas saludables ayuda a mantener la saciedad por más tiempo.","Es una ensalada baja en calorías y alta en nutrientes, perfecta para una dieta equilibrada.","Los ingredientes frescos y naturales ayudan a reducir la retención de líquidos y a mejorar la digestión."]'::jsonb),
(gen_random_uuid(), 'Ternera salteada con brócoli', 'Almuerzo', '/images/r_almuerzo_3.png', 450, 45, 10, 25, 20, '{"Principal":["500g de ternera magra, cortada en tiras","300g de brócoli, cortado en floretes","2 cucharadas de aceite de oliva","2 dientes de ajo, picados","1 cucharada de salsa de soja baja en sodio","1 cucharadita de jengibre fresco, rallado"],"Opcional":["Semillas de sésamo para decorar","Cebollino picado para decorar"]}'::jsonb, '["Calienta una sartén grande a fuego medio-alto y añade el aceite de oliva.","Agrega el ajo picado y el jengibre rallado, y sofríe durante 1 minuto hasta que estén fragantes.","Incorpora las tiras de ternera y cocina, removiendo ocasionalmente, hasta que estén doradas por todos lados, aproximadamente 5-7 minutos.","Añade los floretes de brócoli a la sartén y cocina por otros 3-4 minutos, hasta que estén tiernos pero crujientes.","Vierte la salsa de soja sobre la mezcla y revuelve bien para que se impregne todos los ingredientes.","Retira del fuego y sirve caliente, decorando con semillas de sésamo y cebollino si lo deseas."]'::jsonb, 'Disfruta de esta deliciosa ternera salteada con brócoli, una combinación perfecta de sabores y nutrientes que te llenará de energía y satisfacción. Ideal para un almuerzo saludable y equilibrado.', '["Corta la ternera en tiras finas para que se cocine de manera uniforme y rápida.","No sobrecargues la sartén; si es necesario, cocina la ternera en dos tandas para asegurar un dorado perfecto.","Blanquea el brócoli en agua hirviendo durante 1-2 minutos antes de agregarlo a la sartén para mantener su color vibrante y textura crujiente."]'::jsonb, '["Utiliza pollo o tofu en lugar de ternera para una opción diferente y saludable.","Sustituye la salsa de soja por tamari para una versión sin gluten.","Prueba con col rizada o espinacas en lugar de brócoli para variar los vegetales."]'::jsonb, '["La ternera es rica en proteínas de alta calidad, esenciales para la reparación y el crecimiento muscular.","El brócoli aporta fibra y antioxidantes, ayudando a la digestión y fortaleciendo el sistema inmunológico.","El jengibre tiene propiedades antiinflamatorias y puede ayudar a mejorar la circulación."]'::jsonb, '["Bajo en calorías, este plato es nutritivo y saciante, ayudando a controlar el apetito.","La alta cantidad de proteínas promueve la saciedad y puede ayudar a mantener la masa muscular durante la pérdida de peso.","El brócoli es bajo en carbohidratos y alto en fibra, lo que contribuye a la sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Bowl de lentejas y arroz', 'Almuerzo', '/images/r_almuerzo_4.png', 410, 20, 60, 5, 25, '{"Principal":["1 taza de lentejas verdes","1 taza de arroz integral","1 cebolla mediana, picada","2 dientes de ajo, picados","1 zanahoria, picada en cubos","4 tazas de caldo de verduras","2 cucharadas de aceite de oliva","1 cucharadita de comino","Sal y pimienta al gusto"],"Opcional":["1 pimiento rojo, picado","1 aguacate, en rodajas","Cilantro fresco para decorar"]}'::jsonb, '["Enjuaga las lentejas bajo agua fría y escúrrelas bien.","En una olla grande, calienta el aceite de oliva a fuego medio y añade la cebolla, el ajo y la zanahoria. Sofríe durante unos 5 minutos hasta que estén tiernos.","Agrega las lentejas y el arroz integral a la olla, junto con el caldo de verduras, el comino, la sal y la pimienta. Lleva a ebullición.","Reduce el fuego a bajo y cubre la olla. Cocina a fuego lento durante unos 30-35 minutos, o hasta que las lentejas y el arroz estén tiernos.","Si usas pimiento rojo, agrégalo en los últimos 10 minutos de cocción para que mantenga su textura.","Una vez cocido, retira del fuego y deja reposar durante 5 minutos antes de servir. Decora con rodajas de aguacate y cilantro fresco si lo deseas."]'::jsonb, 'Disfruta de un bowl de lentejas y arroz que no solo es delicioso, sino también nutritivo y saciante. Este plato es perfecto para reponer energías y cuidar de tu bienestar.', '["Para una textura más cremosa, puedes aplastar ligeramente algunas lentejas antes de servir.","Si deseas un sabor más profundo, tuesta el arroz en la olla con un poco de aceite antes de agregar el caldo.","Añadir un chorrito de limón al final realzará los sabores del plato."]'::jsonb, '["Puedes sustituir el arroz integral por quinoa para un aporte extra de proteínas.","Las lentejas verdes pueden ser reemplazadas por lentejas rojas si prefieres un tiempo de cocción más corto.","Usa caldo de pollo en lugar de caldo de verduras para un sabor diferente."]'::jsonb, '["Las lentejas son ricas en proteínas y fibra, lo que ayuda a mantener la saciedad.","El arroz integral proporciona carbohidratos complejos que ofrecen energía sostenida.","Este bowl es una excelente fuente de hierro y folato, beneficiosos para la salud sanguínea."]'::jsonb, '["La alta cantidad de fibra en las lentejas y el arroz integral ayuda a regular el apetito.","Este plato es bajo en calorías y muy nutritivo, ideal para mantener un déficit calórico saludable.","La combinación de proteínas y carbohidratos complejos ayuda a estabilizar los niveles de azúcar en sangre, reduciendo antojos."]'::jsonb),
(gen_random_uuid(), 'Pasta integral con pollo y tomate', 'Almuerzo', '/images/r_almuerzo_5.png', 430, 35, 50, 8, 20, '{"Principal":["200g de pasta integral","150g de pechuga de pollo","400g de tomate triturado","1 cebolla mediana","2 dientes de ajo","1 cucharada de aceite de oliva","Sal al gusto","Pimienta al gusto","Albahaca fresca al gusto"],"Opcional":["Queso parmesano rallado al gusto","Pimiento rojo en tiras","Aceitunas negras"]}'::jsonb, '["Cocina la pasta integral en agua hirviendo con sal según las instrucciones del paquete hasta que esté al dente.","Mientras se cocina la pasta, corta la pechuga de pollo en cubos y sazona con sal y pimienta.","En una sartén grande, calienta el aceite de oliva a fuego medio y agrega la cebolla picada y los dientes de ajo picados. Sofríe hasta que estén dorados.","Añade los cubos de pollo a la sartén y cocina hasta que estén completamente dorados y cocidos por dentro.","Incorpora el tomate triturado y cocina a fuego lento durante 10 minutos, permitiendo que los sabores se mezclen bien.","Una vez que la pasta esté lista, escúrrela y agrégala a la sartén con la salsa de pollo y tomate. Mezcla bien y sirve caliente con albahaca fresca por encima."]'::jsonb, 'Disfruta de una deliciosa pasta integral con pollo y tomate, una combinación perfecta que nutre tu cuerpo y deleita tu paladar. Ideal para un almuerzo lleno de energía y sabor.', '["Para un sabor más profundo, puedes asar los tomates antes de triturarlos.","Cocina la pasta un minuto menos de lo indicado para que termine de cocerse en la salsa.","Añadir un toque de vino blanco al pollo mientras se cocina puede realzar los sabores."]'::jsonb, '["Sustituye la pasta integral por quinoa para un aporte proteico adicional.","Utiliza pechuga de pavo en lugar de pollo para una opción más magra.","Cambia el tomate triturado por salsa de tomate casera para un sabor más fresco."]'::jsonb, '["La pasta integral es rica en fibra, lo que ayuda a la digestión.","El pollo es una excelente fuente de proteínas magras, ideal para el desarrollo muscular.","Los tomates son ricos en antioxidantes, como el licopeno, que promueven la salud del corazón."]'::jsonb, '["La fibra de la pasta integral te mantiene saciado por más tiempo, ayudando a controlar el apetito.","El pollo magro proporciona proteínas sin muchas calorías, promoviendo la pérdida de grasa.","Las comidas ricas en verduras y legumbres, como esta receta, son bajas en calorías y altas en nutrientes."]'::jsonb),
(gen_random_uuid(), 'Salmón con batata asada', 'Almuerzo', '/images/r_almuerzo_6.png', 460, 35, 40, 18, 30, '{"Principal":["2 filetes de salmón (aproximadamente 150 g cada uno)","2 batatas medianas","2 cucharadas de aceite de oliva","1 cucharadita de sal","1/2 cucharadita de pimienta negra","1 cucharadita de pimentón dulce"],"Opcional":["1 limón (en rodajas, para decorar)","Hierbas frescas como perejil o eneldo"]}'::jsonb, '["Precalienta el horno a 200°C (400°F).","Lava las batatas y pélalas, luego córtalas en cubos de aproximadamente 2 cm.","En un tazón, mezcla los cubos de batata con 1 cucharada de aceite de oliva, sal, pimienta y pimentón dulce.","Extiende las batatas en una bandeja para hornear y hornéalas durante 20 minutos.","Mientras las batatas se asan, prepara el salmón. Sazona los filetes con la cucharada restante de aceite de oliva, sal y pimienta.","Después de 20 minutos, saca la bandeja del horno y coloca los filetes de salmón sobre las batatas. Hornea todo junto durante 15 minutos más, o hasta que el salmón esté completamente cocido."]'::jsonb, 'Deléitate con este salmón jugoso y batata asada, una combinación perfecta que no solo es deliciosa, sino también nutritiva y reconfortante.', '["Para un sabor extra, marinar el salmón en salsa de soja y jengibre durante 30 minutos antes de cocinar.","Asegúrate de no sobrecocinar el salmón; debe desmenuzarse fácilmente con un tenedor pero aún estar jugoso.","Puedes agregar otras verduras como brócoli o espárragos a la bandeja para aumentar la cantidad de nutrientes."]'::jsonb, '["Sustituye el salmón por trucha o tilapia para variar el sabor.","Usa aceite de aguacate en lugar de aceite de oliva para un perfil de sabor diferente.","Cambia las batatas por calabacín para una opción más baja en carbohidratos."]'::jsonb, '["El salmón es rico en ácidos grasos omega-3, que son excelentes para la salud del corazón.","Las batatas son una gran fuente de fibra y antioxidantes, lo que ayuda a la digestión.","Este plato es alto en proteínas, lo que promueve la saciedad y ayuda a mantener la masa muscular."]'::jsonb, '["La combinación de proteínas y fibra en esta comida ayuda a controlar el hambre y reduce los antojos.","Las batatas tienen un índice glucémico bajo, lo que ayuda a mantener estables los niveles de azúcar en la sangre.","El salmón puede aumentar el metabolismo debido a su contenido de proteínas y grasas saludables."]'::jsonb),
(gen_random_uuid(), 'Ensalada de garbanzos', 'Almuerzo', '/images/r_almuerzo_7.png', 390, 15, 45, 12, 10, '{"Principal":["400g de garbanzos cocidos","150g de tomate cherry, cortados por la mitad","1 pepino, picado en cubos","1 pimiento rojo, picado","1/2 cebolla morada, finamente picada","50g de queso feta desmenuzado","30g de aceitunas negras, en rodajas","1 manojo de perejil fresco, picado"],"Opcional":["1 aguacate, cortado en cubos","1 cucharadita de comino en polvo","Jugo de 1 limón"]}'::jsonb, '["Enjuaga los garbanzos cocidos bajo agua fría y escúrrelos bien.","En un tazón grande, combina los garbanzos, los tomates cherry, el pepino, el pimiento rojo y la cebolla morada.","Agrega las aceitunas y el perejil picado al tazón, mezclando suavemente para no deshacer los ingredientes.","Si decides usar aguacate, incorpóralo en este paso para que no se aplaste.","Aliña la ensalada con jugo de limón, comino en polvo y una pizca de sal y pimienta al gusto.","Finalmente, espolvorea el queso feta desmenuzado por encima y mezcla nuevamente antes de servir."]'::jsonb, 'Disfruta de una explosión de sabores y nutrientes en cada bocado de esta colorida ensalada de garbanzos, perfecta para mantenerte lleno de energía durante todo el día.', '["Deja los garbanzos en remojo durante la noche antes de cocerlos para mejorar su textura y digestibilidad.","Corta los vegetales en tamaños uniformes para asegurar una presentación atractiva y una mezcla homogénea de sabores.","Refréscate en el refrigerador durante al menos 30 minutos antes de servir para que los sabores se integren adecuadamente."]'::jsonb, '["Sustituye el queso feta por queso de cabra para un sabor más intenso.","Usa garbanzos enlatados si buscas una opción más rápida y conveniente.","Cambia el perejil por albahaca fresca para un toque diferente."]'::jsonb, '["Los garbanzos son ricos en proteínas y fibra, lo que ayuda a mantener la saciedad.","El pepino aporta hidratación y bajo contenido calórico, ideal para dietas de control de peso.","El queso feta proporciona calcio y proteínas, esenciales para la salud ósea."]'::jsonb, '["La alta cantidad de fibra en esta ensalada ayuda a regular el tránsito intestinal y promueve la sensación de saciedad.","Las grasas saludables del aguacate (si se incluye) contribuyen a equilibrar el hambre y a evitar picoteos innecesarios.","La combinación de ingredientes frescos y nutritivos asegura un bajo contenido calórico sin sacrificar el sabor."]'::jsonb),
(gen_random_uuid(), 'Fajitas saludables de pollo', 'Almuerzo', '/images/r_almuerzo_8.png', 440, 35, 40, 15, 20, '{"Principal":["500g de pechuga de pollo, cortada en tiras","2 pimientos (uno rojo y uno verde), cortados en tiras","1 cebolla grande, cortada en plumas","2 cucharadas de aceite de oliva","1 cucharadita de comino","1 cucharadita de pimentón dulce","Sal y pimienta al gusto","8 tortillas integrales"],"Opcional":["Aguacate en rodajas","Cilantro fresco picado","Salsa picante al gusto"]}'::jsonb, '["Calienta el aceite de oliva en una sartén grande a fuego medio-alto.","Agrega las tiras de pollo y sazona con sal, pimienta, comino y pimentón. Cocina hasta que el pollo esté dorado y completamente cocido, aproximadamente 7-8 minutos.","Retira el pollo de la sartén y reserva en un plato.","En la misma sartén, añade los pimientos y la cebolla. Sofríe hasta que estén tiernos y ligeramente caramelizados, alrededor de 5 minutos.","Vuelve a agregar el pollo a la sartén con las verduras y mezcla bien para combinar los sabores. Cocina por 2 minutos más.","Calienta las tortillas integrales en una sartén aparte o en el microondas. Sirve la mezcla de pollo y verduras en las tortillas y añade los ingredientes opcionales al gusto."]'::jsonb, 'Disfruta de estas deliciosas fajitas saludables de pollo, llenas de sabor y color, perfectas para un almuerzo nutritivo que te mantendrá activo durante el día.', '["Marina el pollo en las especias durante al menos 30 minutos antes de cocinar para realzar el sabor.","Utiliza una sartén antiadherente para evitar que los ingredientes se peguen y facilitar la limpieza.","Corta los pimientos y la cebolla en tamaños uniformes para asegurar una cocción pareja."]'::jsonb, '["Sustituye el pollo por tofu o tempeh para una opción vegetariana.","Utiliza tortillas de col rizada en lugar de tortillas integrales para una opción más baja en carbohidratos.","Cambia los pimientos por calabacines o champiñones para variar el sabor."]'::jsonb, '["La pechuga de pollo es una excelente fuente de proteínas magras, que ayuda a la construcción muscular.","Los pimientos son ricos en vitamina C y antioxidantes, lo que fortalece el sistema inmunológico.","Las tortillas integrales aportan fibra, que favorece la digestión y la saciedad."]'::jsonb, '["Las comidas ricas en proteínas como el pollo aumentan la sensación de saciedad, lo que puede ayudar a controlar el apetito.","El alto contenido de fibra en las tortillas integrales y los vegetales promueve una digestión saludable y prolonga la saciedad.","Cocinar en casa permite controlar los ingredientes y las porciones, ayudando a mantener un déficit calórico."]'::jsonb),
(gen_random_uuid(), 'Pescado blanco al papillote', 'Almuerzo', '/images/r_almuerzo_9.png', 320, 30, 20, 10, 25, '{"Principal":["400g de filete de pescado blanco (merluza, lenguado o tilapia)","2 ramas de romero fresco","1 limón (en rodajas)","2 dientes de ajo (finamente picados)","2 cucharadas de aceite de oliva","Sal y pimienta al gusto"],"Opcional":["1 zanahoria (en tiras finas)","1 pimiento rojo (en tiras)","1 calabacín (en rodajas)"]}'::jsonb, '["Precalienta el horno a 180°C (350°F).","Corta dos hojas grandes de papel de aluminio y colócalas en una bandeja para hornear.","Coloca el filete de pescado en el centro de cada hoja de papel de aluminio.","Agrega las rodajas de limón, el ajo picado y las ramas de romero encima del pescado.","Rocía el pescado con aceite de oliva y sazona con sal y pimienta al gusto.","Si decides usar verduras opcionales, colócalas alrededor del pescado antes de cerrar el papillote.","Cierra las hojas de papel de aluminio formando un paquete hermético y hornea durante 20-25 minutos, hasta que el pescado esté cocido y tierno."]'::jsonb, 'Disfruta de un delicioso pescado blanco al papillote, una forma saludable y sabrosa de cocinar que conserva todos los sabores y nutrientes. Ideal para un almuerzo ligero y lleno de energía.', '["Asegúrate de no sobrecocinar el pescado, ya que puede volverse seco; debe desmenuzarse fácilmente con un tenedor.","Puedes experimentar con diferentes hierbas y especias, como eneldo o tomillo, para darle un toque personal a tu receta.","Si no tienes papel de aluminio, puedes usar papel pergamino, que también es excelente para cocinar al papillote."]'::jsonb, '["Sustituye el pescado blanco por salmón o trucha para un aporte extra de omega-3.","Utiliza aceite de aguacate en lugar de aceite de oliva para un sabor diferente y beneficios adicionales.","Reemplaza el romero por albahaca fresca para un perfil de sabor más ligero y fresco."]'::jsonb, '["El pescado blanco es una excelente fuente de proteínas magras, lo que ayuda a mantener la masa muscular.","Rico en ácidos grasos omega-3, que son beneficiosos para la salud cardiovascular.","Las verduras agregadas aportan fibra, vitaminas y antioxidantes, esenciales para una dieta equilibrada."]'::jsonb, '["Bajo en calorías y alto en proteínas, el pescado blanco ayuda a sentirse lleno por más tiempo.","Cocinar al papillote retiene los nutrientes y sabores, lo que permite disfrutar de comidas saludables sin la necesidad de salsas pesadas.","Las verduras adicionales aumentan el volumen de la comida sin agregar muchas calorías, favoreciendo un déficit calórico."]'::jsonb),
(gen_random_uuid(), 'Guiso ligero de pavo', 'Almuerzo', '/images/r_almuerzo_10.png', 380, 35, 25, 12, 30, '{"Principal":["500g de carne de pavo picada","1 cebolla mediana, picada","2 dientes de ajo, picados","1 zanahoria grande, en cubos","1 pimiento rojo, en cubos","300g de calabacín, en cubos","400ml de caldo de pollo bajo en sodio","1 lata (400g) de tomates triturados","1 cucharadita de pimentón dulce","Sal y pimienta al gusto","2 cucharadas de aceite de oliva"],"Opcional":["1 hoja de laurel","Perejil fresco picado para decorar"]}'::jsonb, '["En una olla grande, calienta el aceite de oliva a fuego medio. Agrega la cebolla y el ajo, y sofríe hasta que estén tiernos y fragantes, aproximadamente 3 minutos.","Añade la carne de pavo picada a la olla, cocinando hasta que esté dorada y cocida por completo, alrededor de 5-7 minutos.","Incorpora la zanahoria, el pimiento rojo y el calabacín, y cocina por unos 5 minutos más, removiendo ocasionalmente.","Vierte el caldo de pollo y los tomates triturados en la olla, y agrega el pimentón dulce, la sal y la pimienta. Si lo deseas, añade la hoja de laurel.","Lleva la mezcla a ebullición, luego reduce el fuego y deja que se cocine a fuego lento durante 20 minutos, permitiendo que los sabores se mezclen.","Antes de servir, retira la hoja de laurel y ajusta la sazón si es necesario. Decora con perejil fresco picado si lo deseas."]'::jsonb, 'Disfruta de un guiso ligero de pavo, lleno de sabor y nutrientes, perfecto para mantenerte satisfecho sin sentirte pesado. Este plato reconfortante es ideal para un almuerzo saludable y delicioso.', '["Para un guiso más espeso, puedes triturar un poco del guiso y mezclarlo de nuevo.","Usa carne de pavo magra para mantener el plato ligero y bajo en grasas.","Asegúrate de no sobrecocinar las verduras para que mantengan su textura y nutrientes."]'::jsonb, '["Puedes reemplazar la carne de pavo por pollo o carne magra de res.","Utiliza caldo de verduras en lugar de caldo de pollo para una opción vegetariana.","Sustituye los tomates triturados por salsa de tomate sin azúcar añadida."]'::jsonb, '["El pavo es una excelente fuente de proteínas magras, lo que ayuda a construir y reparar tejidos.","Las verduras aportan fibra, vitaminas y minerales esenciales, favoreciendo la digestión.","El uso de aceite de oliva proporciona grasas saludables que benefician la salud cardiovascular."]'::jsonb, '["Este guiso es bajo en calorías, lo que permite una porción generosa sin comprometer tu ingesta calórica diaria.","La alta cantidad de proteínas y fibra ayuda a mantener la saciedad por más tiempo, reduciendo la necesidad de picar entre comidas.","Los ingredientes frescos y nutritivos ayudan a acelerar el metabolismo y mejorar el bienestar general."]'::jsonb),
(gen_random_uuid(), 'Poke bowl de tofu', 'Almuerzo', '/images/r_almuerzo_11.png', 400, 20, 50, 14, 15, '{"Principal":["200g de tofu firme","1 taza de arroz integral cocido","1/2 aguacate","1/2 taza de edamame cocido","1/2 taza de zanahoria rallada","1/4 de pepino en rodajas","2 cucharadas de salsa de soja baja en sodio","1 cucharada de aceite de sésamo"],"Opcional":["Semillas de sésamo para decorar","Cebollino picado","Rodajas de jengibre encurtido"]}'::jsonb, '["Escurre y presiona el tofu para eliminar el exceso de agua, luego córtalo en cubos de aproximadamente 2 cm.","Calienta una sartén antiadherente a fuego medio y añade el aceite de sésamo. Agrega el tofu y cocina hasta que esté dorado y crujiente por todos lados, aproximadamente 10 minutos.","Mientras tanto, cocina el arroz integral según las instrucciones del paquete y déjalo enfriar.","En un tazón grande, mezcla el arroz integral con la salsa de soja, asegurándote de que esté bien distribuida.","Añade el tofu dorado al tazón con arroz, junto con el edamame, la zanahoria rallada, el aguacate y el pepino.","Decora con semillas de sésamo y cebollino picado antes de servir. ¡Disfruta de tu Poke Bowl de Tofu lleno de sabor!"]'::jsonb, 'Disfruta de un refrescante Poke Bowl de Tofu, lleno de colores y sabores que energizan tu día. Este plato no solo es delicioso, sino que también es una excelente opción para cuidar tu bienestar.', '["Para obtener un tofu más crujiente, puedes marinarlo en salsa de soja antes de cocinarlo.","Cocina el arroz con un poco de caldo de verduras para añadir más sabor.","Asegúrate de no sobrecocinar el tofu para mantener su textura perfecta."]'::jsonb, '["Reemplaza el tofu por tempeh para una opción más rica en proteínas.","Utiliza quinoa en lugar de arroz integral para un perfil nutricional diferente.","Sustituye la salsa de soja por tamari para una versión sin gluten."]'::jsonb, '["El tofu es una excelente fuente de proteínas vegetales y contiene todos los aminoácidos esenciales.","El aguacate aporta grasas saludables que son beneficiosas para el corazón.","El edamame es rico en fibra y antioxidantes, lo que ayuda a la salud digestiva."]'::jsonb, '["El alto contenido de fibra en el arroz integral y las verduras ayuda a mantener la saciedad por más tiempo.","La proteína del tofu contribuye a la construcción muscular, lo que puede aumentar el metabolismo.","Las grasas saludables del aguacate pueden ayudar a regular el apetito y reducir antojos."]'::jsonb),
(gen_random_uuid(), 'Berenjena rellena de carne picada', 'Almuerzo', '/images/r_almuerzo_12.png', 410, 35, 15, 20, 40, '{"Principal":["2 berenjenas medianas","300 g de carne picada (ternera o pavo)","1 cebolla picada","2 dientes de ajo picados","400 g de tomate triturado","100 g de queso rallado bajo en grasa","1 cucharadita de orégano","1 cucharadita de pimentón dulce","Sal y pimienta al gusto"],"Opcional":["Perejil fresco picado para decorar","Aceite de oliva virgen extra para saltear","1 pimiento rojo picado"]}'::jsonb, '["Precalienta el horno a 180°C (350°F).","Corta las berenjenas por la mitad a lo largo y saca la pulpa con una cuchara, dejando un borde de aproximadamente 1 cm.","Pica la pulpa de la berenjena y resérvala. En una sartén grande, calienta un poco de aceite de oliva y sofríe la cebolla y el ajo hasta que estén dorados.","Agrega la carne picada a la sartén y cocina hasta que esté bien dorada, luego añade la pulpa de berenjena y el pimiento rojo (si lo usas), cocinando por unos minutos.","Incorpora el tomate triturado, el orégano, el pimentón, la sal y la pimienta. Cocina a fuego lento durante 10 minutos.","Rellena las mitades de berenjena con la mezcla de carne, espolvorea el queso rallado por encima y hornea durante 25-30 minutos, o hasta que las berenjenas estén tiernas y el queso dorado."]'::jsonb, 'Disfruta de una deliciosa berenjena rellena de carne picada, una combinación perfecta de sabores que te hará sentir satisfecho y lleno de energía. Esta receta es ideal para un almuerzo nutritivo y reconfortante.', '["Asegúrate de escurrir el exceso de líquido de la mezcla de carne antes de rellenar las berenjenas para evitar que queden aguadas.","Puedes asar las berenjenas antes de rellenarlas para intensificar su sabor.","Experimenta con diferentes hierbas y especias para personalizar el sabor a tu gusto."]'::jsonb, '["Sustituye la carne picada por tofu o tempeh para una opción vegetariana.","Utiliza queso vegano o bajo en grasa si deseas reducir las calorías.","Cambia el tomate triturado por salsa de tomate casera sin azúcar añadido."]'::jsonb, '["Las berenjenas son ricas en fibra, lo que ayuda a la digestión y promueve la saciedad.","La carne magra es una excelente fuente de proteínas, esenciales para la reparación y el crecimiento muscular.","Los tomates son ricos en antioxidantes, como el licopeno, que ayudan a combatir el daño celular."]'::jsonb, '["Bajo en calorías y alto en fibra, este plato te mantiene lleno por más tiempo, evitando picos de hambre.","La proteína en la carne magra ayuda a aumentar la saciedad y a conservar la masa muscular durante la pérdida de peso.","La combinación de vegetales y proteínas magras apoya un metabolismo saludable, facilitando la quema de grasa."]'::jsonb),
(gen_random_uuid(), 'Wrap de salmón ahumado', 'Almuerzo', '/images/r_almuerzo_13.png', 380, 25, 35, 15, 5, '{"Principal":["1 tortilla integral (de aproximadamente 70g)","100g de salmón ahumado","50g de queso crema bajo en grasa","1/2 aguacate, en rodajas","50g de espinacas frescas","1/2 pepino, en rodajas finas"],"Opcional":["1 cucharadita de eneldo fresco picado","Zumo de limón al gusto","Pimienta negra al gusto"]}'::jsonb, '["Coloca la tortilla integral sobre una superficie plana y extiende el queso crema uniformemente por toda la superficie.","Distribuye el salmón ahumado sobre el queso crema, asegurándote de cubrir bien la tortilla.","Agrega las rodajas de aguacate, las espinacas frescas y las rodajas de pepino en el centro de la tortilla.","Si deseas, espolvorea el eneldo fresco y añade un chorrito de zumo de limón para realzar el sabor.","Con cuidado, enrolla la tortilla desde un extremo, asegurándote de que el relleno quede bien apretado.","Corta el wrap en mitades y sírvelo inmediatamente, o envuélvelo para llevar."]'::jsonb, 'Disfruta de un wrap de salmón ahumado que combina frescura y sabor en cada bocado, ideal para un almuerzo ligero y nutritivo.', '["Para un wrap más crujiente, calienta la tortilla en una sartén durante unos segundos antes de agregar los ingredientes.","Utiliza salmón ahumado de buena calidad para asegurar un mejor sabor y frescura.","No escatimes en el zumo de limón; realza el sabor del aguacate y el salmón."]'::jsonb, '["Sustituye el salmón ahumado por pollo a la parrilla para una opción diferente.","Cambia el queso crema por hummus para una alternativa vegana y rica en proteínas.","Utiliza una tortilla de espinaca en lugar de una tortilla integral para añadir más nutrientes."]'::jsonb, '["El salmón ahumado es rico en ácidos grasos omega-3, que son beneficiosos para la salud del corazón.","El aguacate proporciona grasas saludables y fibra, lo que ayuda a mantener la saciedad.","Las espinacas son una excelente fuente de vitaminas y minerales, como el hierro y la vitamina K."]'::jsonb, '["Este wrap es bajo en calorías y alto en nutrientes, lo que ayuda a mantener una dieta equilibrada.","La combinación de proteínas del salmón y grasas saludables del aguacate promueve la sensación de saciedad, reduciendo el deseo de comer en exceso.","Las fibras de las verduras ayudan a regular la digestión y a mantener un metabolismo saludable."]'::jsonb),
(gen_random_uuid(), 'Arroz frito saludable de coliflor', 'Almuerzo', '/images/r_almuerzo_14.png', 310, 25, 15, 12, 15, '{"Principal":["1 cabeza de coliflor","2 cucharadas de aceite de oliva","2 huevos","1 zanahoria, picada en cubos pequeños","1 pimiento rojo, picado","2 dientes de ajo, picados","3 cebollas verdes, picadas","3 cucharadas de salsa de soya baja en sodio","Sal y pimienta al gusto"],"Opcional":["1 taza de guisantes","1 cucharadita de jengibre fresco, rallado","Cilantro fresco para decorar"]}'::jsonb, '["Lava y seca la coliflor, luego córtala en floretes y procésala en un procesador de alimentos hasta que tenga una textura similar al arroz.","En una sartén grande, calienta el aceite de oliva a fuego medio-alto. Agrega el ajo y el jengibre, y sofríe durante un minuto hasta que estén fragantes.","Incorpora la zanahoria y el pimiento rojo a la sartén, y cocina durante 3-4 minutos hasta que estén tiernos.","Empuja las verduras a un lado de la sartén y agrega los huevos batidos en el espacio libre. Revuelve hasta que estén cocidos y luego mezcla con las verduras.","Añade la coliflor procesada a la sartén y vierte la salsa de soya. Mezcla todo bien y cocina durante 5-7 minutos, removiendo ocasionalmente.","Finalmente, ajusta la sal y pimienta al gusto, y decora con cebollas verdes y cilantro fresco antes de servir."]'::jsonb, 'Disfruta de un delicioso arroz frito de coliflor que no solo satisface tu paladar, sino que también nutre tu cuerpo. Esta opción baja en carbohidratos es perfecta para un almuerzo saludable y energético.', '["Para una textura más crujiente, asegúrate de no sobrecocinar la coliflor.","Puedes preparar el arroz de coliflor con anticipación y guardarlo en el refrigerador para una comida rápida durante la semana.","Utiliza una sartén antiadherente para evitar que los ingredientes se peguen y facilitar la limpieza."]'::jsonb, '["Sustituye el aceite de oliva por aceite de coco para un sabor diferente.","Puedes usar tofu en lugar de huevos para una opción vegana.","El arroz integral puede ser una alternativa si prefieres un plato más tradicional."]'::jsonb, '["La coliflor es rica en fibra, lo que ayuda a la digestión y promueve la saciedad.","Los huevos son una excelente fuente de proteínas de alta calidad, esenciales para el mantenimiento muscular.","Los pimientos y zanahorias aportan antioxidantes y vitaminas que benefician la salud ocular y la piel."]'::jsonb, '["Bajo en calorías y carbohidratos, este plato ayuda a reducir la ingesta calórica total.","La alta fibra de la coliflor ayuda a mantener la sensación de saciedad, reduciendo el picoteo entre comidas.","Las proteínas de los huevos ayudan a preservar la masa muscular durante la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Albóndigas de pollo en salsa', 'Almuerzo', '/images/r_almuerzo_15.png', 430, 40, 20, 15, 30, '{"Principal":["500g de pechuga de pollo molida","1 huevo","50g de pan rallado integral","2 dientes de ajo picados","1 cucharadita de sal","1/2 cucharadita de pimienta negra","1 cucharadita de orégano seco","400ml de salsa de tomate natural","1 cebolla picada","2 cucharadas de aceite de oliva"],"Opcional":["Queso parmesano rallado para servir","Albahaca fresca para decorar"]}'::jsonb, '["En un bol grande, mezcla la pechuga de pollo molida, el huevo, el pan rallado, el ajo picado, la sal, la pimienta y el orégano hasta que estén bien combinados.","Forma albóndigas del tamaño de una pelota de golf y colócalas en una bandeja.","Calienta el aceite de oliva en una sartén grande a fuego medio y añade las albóndigas, cocinándolas hasta que estén doradas por todos lados, aproximadamente 5-7 minutos.","Retira las albóndigas de la sartén y reserva. En la misma sartén, añade la cebolla picada y sofríe hasta que esté transparente, unos 3 minutos.","Vierte la salsa de tomate en la sartén y lleva a ebullición. Luego, reduce el fuego y devuelve las albóndigas a la sartén, cocinando a fuego lento durante 15 minutos.","Sirve caliente, espolvoreado con queso parmesano y albahaca fresca si lo deseas."]'::jsonb, 'Disfruta de estas jugosas albóndigas de pollo en una deliciosa salsa que te harán sentir satisfecho y lleno de energía. Perfectas para un almuerzo nutritivo y lleno de sabor.', '["Utiliza pollo fresco y de calidad para obtener un mejor sabor y textura en las albóndigas.","No sobrecocines las albóndigas; deben estar bien cocidas por dentro, pero aún jugosas.","Puedes añadir verduras picadas finamente a la mezcla de albóndigas para aumentar el contenido nutricional."]'::jsonb, '["Sustituir el pan rallado integral por avena molida para una opción sin gluten.","Usar pechuga de pavo molida en lugar de pollo para un sabor diferente y menos grasa.","Reemplazar la salsa de tomate por una salsa de yogur natural con hierbas para una variante más ligera."]'::jsonb, '["El pollo es una excelente fuente de proteínas magras, esencial para la construcción muscular.","La salsa de tomate contiene licopeno, un antioxidante que ayuda a combatir enfermedades.","El ajo tiene propiedades antiinflamatorias y puede fortalecer el sistema inmunológico."]'::jsonb, '["Bajo en calorías, lo que permite una comida satisfactoria sin exceder el límite diario.","Alto en proteínas que ayudan a mantener la saciedad y reducen el hambre.","Las albóndigas son versátiles y pueden ser acompañadas de vegetales, aumentando el volumen de la comida sin añadir muchas calorías."]'::jsonb),
(gen_random_uuid(), 'Ensalada César saludable', 'Almuerzo', '/images/r_almuerzo_16.png', 370, 35, 15, 18, 15, '{"Principal":["150g de pechuga de pollo a la parrilla, cortada en tiras","100g de lechuga romana, lavada y troceada","50g de queso parmesano rallado","50g de croutones integrales","2 cucharadas de aderezo César ligero"],"Opcional":["1 cucharadita de jugo de limón","Pimienta negra al gusto","1 cucharadita de perejil fresco picado"]}'::jsonb, '["Comienza cocinando la pechuga de pollo a la parrilla hasta que esté dorada y bien cocida, luego córtala en tiras.","En un tazón grande, coloca la lechuga romana troceada como base de la ensalada.","Agrega las tiras de pollo a la lechuga y mezcla suavemente.","Espolvorea el queso parmesano rallado sobre la mezcla de pollo y lechuga.","Añade los croutones integrales y mezcla con cuidado para no romper los croutones.","Finaliza añadiendo el aderezo César ligero y mezcla nuevamente. Si deseas, agrega jugo de limón y pimienta negra al gusto."]'::jsonb, 'Disfruta de una deliciosa Ensalada César saludable que combina frescura y sabor en cada bocado, perfecta para nutrir tu cuerpo y deleitar tu paladar.', '["Para una mayor intensidad de sabor, marina el pollo en especias y yogur bajo en grasa antes de cocinarlo.","Utiliza pan integral para hacer tus propios croutones, así podrás controlar la cantidad de aceite y sal.","Asegúrate de secar bien la lechuga para que el aderezo se adhiera mejor a los ingredientes."]'::jsonb, '["Sustituye el pollo por garbanzos asados para una opción vegana.","Usa aguacate en lugar de queso parmesano para añadir cremosidad sin lácteos.","Reemplaza los croutones por semillas de girasol o nueces para un crujido saludable."]'::jsonb, '["Rico en proteínas magras que ayudan en la reparación muscular.","Contiene fibra de la lechuga que promueve una buena digestión.","El queso parmesano aporta calcio necesario para la salud ósea."]'::jsonb, '["Bajo en calorías pero alto en volumen, lo que ayuda a sentirte lleno por más tiempo.","Las proteínas magras del pollo favorecen la saciedad y reducen los antojos.","La fibra de la lechuga y los croutones integrales ayudan a regular el apetito."]'::jsonb),
(gen_random_uuid(), 'Pimientos rellenos de quinoa', 'Almuerzo', '/images/r_almuerzo_17.png', 350, 15, 45, 8, 35, '{"Principal":["4 pimientos rojos","1 taza de quinoa","2 tazas de caldo de verduras","1 lata de frijoles negros (400 g), escurridos y enjuagados","1 taza de maíz dulce","1 cebolla pequeña, picada","2 dientes de ajo, picados","1 cucharadita de comino","1 cucharadita de pimentón dulce"],"Opcional":["1/2 taza de queso rallado (opcional)","Cilantro fresco para decorar","Rodajas de aguacate para servir"]}'::jsonb, '["Precalienta el horno a 180°C (350°F).","Enjuaga la quinoa bajo agua fría y escúrrela. Cocínala en una olla con el caldo de verduras a fuego medio, llevando a ebullición, luego reduce el fuego y cocina a fuego lento durante 15 minutos o hasta que el líquido se absorba.","Mientras se cocina la quinoa, corta la parte superior de los pimientos y retira las semillas y membranas. Reserva.","En una sartén grande, sofríe la cebolla y el ajo a fuego medio hasta que estén dorados y fragantes, aproximadamente 5 minutos.","Agrega los frijoles negros, el maíz, el comino y el pimentón dulce a la sartén, mezclando bien. Incorpora la quinoa cocida y mezcla hasta que todos los ingredientes estén bien combinados.","Rellena cada pimiento con la mezcla de quinoa y colócalos en una bandeja para hornear. Si lo deseas, espolvorea queso rallado por encima.","Hornea los pimientos durante 25-30 minutos o hasta que estén tiernos. Sirve decorados con cilantro fresco y rodajas de aguacate si lo deseas."]'::jsonb, 'Disfruta de unos deliciosos pimientos rellenos de quinoa, una opción colorida y nutritiva que deleitará tu paladar y llenará tu cuerpo de energía positiva.', '["Para un sabor más intenso, tuesta la quinoa en la sartén durante unos minutos antes de cocinarla.","Utiliza pimientos de diferentes colores para hacer el plato más visualmente atractivo y nutritivo.","Asegúrate de que los pimientos estén bien sellados en la parte inferior para evitar que se derrame el relleno durante la cocción."]'::jsonb, '["Puedes reemplazar la quinoa por arroz integral o bulgur.","Los frijoles negros se pueden sustituir por lentejas o garbanzos.","El maíz dulce puede ser reemplazado por guisantes o zanahorias picadas."]'::jsonb, '["La quinoa es una fuente completa de proteínas, lo que la convierte en una excelente opción para vegetarianos y veganos.","Los pimientos son ricos en vitamina C, lo que ayuda a fortalecer el sistema inmunológico.","Los frijoles negros aportan fibra, lo que favorece la salud digestiva."]'::jsonb, '["La quinoa y los frijoles son ricos en proteínas y fibra, lo que ayuda a aumentar la saciedad y reducir el hambre.","Este plato es bajo en calorías y alto en nutrientes, lo que lo hace ideal para quienes desean perder peso de manera saludable.","Los pimientos son bajos en calorías y aportan volumen al plato, ayudando a controlar las porciones sin sentir hambre."]'::jsonb),
(gen_random_uuid(), 'Lomo de cerdo con puré de manzana', 'Almuerzo', '/images/r_almuerzo_18.png', 420, 35, 25, 18, 25, '{"Principal":["600g de lomo de cerdo","2 cucharadas de aceite de oliva","1 cucharadita de sal","1/2 cucharadita de pimienta negra","1 cucharadita de romero fresco picado"],"Opcional":["2 manzanas grandes, peladas y cortadas en trozos","1/4 de taza de agua","1 cucharada de miel (opcional)","Canela al gusto"]}'::jsonb, '["Precalienta el horno a 200°C (400°F).","En una sartén grande, calienta el aceite de oliva a fuego medio-alto. Sazona el lomo de cerdo con sal, pimienta y romero.","Dora el lomo por todos lados en la sartén caliente durante unos 4-5 minutos hasta que esté dorado.","Transfiere el lomo a una bandeja para hornear y hornea durante 20-25 minutos o hasta que la temperatura interna alcance 63°C (145°F).","Mientras el cerdo se hornea, coloca las manzanas en una cacerola con el agua y cocina a fuego medio hasta que estén tiernas, aproximadamente 10-15 minutos.","Tritura las manzanas cocidas con un tenedor o un procesador de alimentos hasta obtener un puré suave. Añade miel y canela al gusto si lo deseas."]'::jsonb, 'Disfruta de un suculento lomo de cerdo acompañado de un suave puré de manzana, una combinación que deleitará tus sentidos y te llenará de energía para el día.', '["Deja reposar el lomo de cerdo unos minutos antes de cortarlo para que los jugos se redistribuyan.","Si deseas un puré más cremoso, puedes añadir un poco de mantequilla o yogur griego al puré de manzana.","Utiliza un termómetro de cocina para asegurarte de que el cerdo esté cocido a la perfección."]'::jsonb, '["Reemplaza el lomo de cerdo por pechuga de pollo para una opción más ligera.","Utiliza puré de peras en lugar de puré de manzana para un sabor diferente.","Sustituye el aceite de oliva por aceite de aguacate."]'::jsonb, '["El lomo de cerdo es una excelente fuente de proteínas magras, esenciales para la reparación muscular.","Las manzanas son ricas en fibra, lo que ayuda a la digestión y promueve la saciedad.","El romero contiene antioxidantes que pueden ayudar a reducir la inflamación."]'::jsonb, '["La combinación de proteínas magras y fibra te mantiene saciado por más tiempo, reduciendo el deseo de comer entre comidas.","El puré de manzana es bajo en calorías y puede ser una alternativa más saludable a los acompañamientos pesados.","Cocinar en casa permite controlar los ingredientes y las porciones, favoreciendo un enfoque más saludable a la alimentación."]'::jsonb),
(gen_random_uuid(), 'Cazuela de alubias blancas', 'Almuerzo', '/images/r_almuerzo_19.png', 390, 20, 50, 6, 20, '{"Principal":["400g de alubias blancas (pueden ser enlatadas o cocidas)","1 cebolla mediana, picada","2 dientes de ajo, picados","1 zanahoria grande, en cubos","1 pimiento rojo, en cubos","400g de tomate triturado","500ml de caldo de verduras","2 cucharadas de aceite de oliva","1 cucharadita de pimentón dulce","Sal y pimienta al gusto","Perejil fresco picado para decorar"],"Opcional":["1 hoja de laurel","1 cucharadita de comino","Chili en polvo al gusto"]}'::jsonb, '["En una cacerola grande, calienta el aceite de oliva a fuego medio y añade la cebolla y el ajo. Sofríe durante unos 3-4 minutos hasta que estén dorados.","Agrega la zanahoria y el pimiento rojo, y cocina por otros 5 minutos, removiendo ocasionalmente.","Incorpora el pimentón dulce y mezcla bien para que se infunda en las verduras.","Añade las alubias blancas, el tomate triturado y el caldo de verduras. Si deseas, agrega la hoja de laurel y el comino.","Lleva la mezcla a ebullición, luego reduce el fuego y cocina a fuego lento durante 20-25 minutos, permitiendo que los sabores se combinen.","Retira la hoja de laurel, sazona con sal y pimienta al gusto y sirve caliente, decorado con perejil fresco picado."]'::jsonb, 'Disfruta de esta deliciosa cazuela de alubias blancas, una combinación perfecta de sabores que te llenará de energía y bienestar. Ideal para un almuerzo nutritivo y reconfortante que te hará sentir satisfecho y feliz.', '["Para una textura más cremosa, puedes triturar una parte de las alubias antes de añadirlas a la cazuela.","Si usas alubias secas, asegúrate de remojarlas durante la noche y cocerlas correctamente antes de añadirlas al plato.","Experimenta con hierbas frescas como el tomillo o el romero para darle un toque diferente a la cazuela."]'::jsonb, '["Puedes sustituir las alubias blancas por garbanzos o alubias negras para variar el sabor y la textura.","El caldo de verduras puede ser reemplazado por caldo de pollo bajo en sodio si no eres vegetariano.","Sustituye el pimiento rojo por calabacín o espinacas para agregar más vegetales."]'::jsonb, '["Las alubias blancas son ricas en fibra, lo que ayuda a la digestión y a mantener la sensación de saciedad.","Contienen proteínas vegetales que son esenciales para la reparación y el crecimiento muscular.","Son una excelente fuente de antioxidantes, que ayudan a combatir el daño celular y reducen el riesgo de enfermedades."]'::jsonb, '["La alta cantidad de fibra en las alubias blancas ayuda a controlar el apetito, lo que puede resultar en una menor ingesta calórica.","Este plato es bajo en grasas y alto en nutrientes, lo que lo convierte en una opción ideal para aquellos que buscan perder peso.","La combinación de proteínas y fibra proporciona energía sostenida, evitando los picos de hambre y el picoteo entre comidas."]'::jsonb),
(gen_random_uuid(), 'Pechuga pavo con verduras asadas', 'Almuerzo', '/images/r_almuerzo_20.png', 360, 35, 20, 10, 25, '{"Principal":["400g de pechuga de pavo","2 cucharadas de aceite de oliva","1 cucharadita de sal","1/2 cucharadita de pimienta negra","1 cucharadita de pimentón dulce"],"Vegetales":["1 pimiento rojo, cortado en tiras","1 pimiento amarillo, cortado en tiras","1 calabacín, en rodajas","1 berenjena, en cubos","1 cebolla, cortada en cuartos"],"Opcional":["1 cucharadita de hierbas provenzales","1 diente de ajo picado"]}'::jsonb, '["Precalienta el horno a 200°C (390°F).","En un bol, mezcla las verduras (pimientos, calabacín, berenjena y cebolla) con 1 cucharada de aceite de oliva, sal, pimienta y las hierbas provenzales si lo deseas.","Coloca las verduras en una bandeja para hornear y hornea durante 20 minutos.","Mientras tanto, prepara la pechuga de pavo aliñándola con la otra cucharada de aceite de oliva, sal, pimienta y pimentón dulce.","Retira las verduras del horno, añade la pechuga de pavo a la bandeja y hornea todo junto por otros 25-30 minutos, o hasta que el pavo esté bien cocido.","Deja reposar la pechuga de pavo durante 5 minutos antes de cortarla en rodajas y servirla con las verduras asadas."]'::jsonb, 'Disfruta de una deliciosa pechuga de pavo jugosa, acompañada de coloridas verduras asadas que no solo son nutritivas, sino que también deleitarán tu paladar.', '["Marina la pechuga de pavo durante al menos 30 minutos antes de cocinarla para potenciar su sabor.","Asegúrate de no sobrecocinar las verduras para que mantengan su textura crujiente y nutrientes.","Utiliza un termómetro de cocina para verificar que la pechuga de pavo alcance 75°C (165°F) en el centro."]'::jsonb, '["Sustituye el pavo por pechuga de pollo para una variante similar.","Puedes usar aceite de aguacate en lugar de aceite de oliva para un sabor diferente y mayor resistencia al calor.","Reemplaza las verduras por cualquier otro vegetal de temporada que prefieras, como espárragos o brócoli."]'::jsonb, '["La pechuga de pavo es rica en proteínas magras, ideal para la construcción muscular.","Las verduras asadas aportan fibra, vitaminas y minerales esenciales para la salud general.","El aceite de oliva contiene grasas saludables que benefician el corazón."]'::jsonb, '["Este platillo es bajo en calorías y alto en proteínas, lo que ayuda a aumentar la saciedad.","Las verduras aportan fibra, lo que favorece la digestión y ayuda a mantener el peso.","La preparación al horno reduce la necesidad de grasas adicionales en comparación con la fritura."]'::jsonb),
(gen_random_uuid(), 'Revuelto de gulas y gambas', 'Almuerzo', '/images/r_almuerzo_21.png', 330, 30, 5, 18, 15, '{"Principal":["200g de gulas","150g de gambas peladas","4 huevos","1 diente de ajo","2 cucharadas de aceite de oliva","Sal al gusto","Pimienta negra al gusto"],"Opcional":["Perejil fresco picado para decorar","Pimiento rojo en tiras para añadir color","Un chorrito de limón para realzar el sabor"]}'::jsonb, '["En una sartén grande, calienta el aceite de oliva a fuego medio y agrega el diente de ajo picado, sofriendo hasta que esté dorado.","Incorpora las gambas peladas y cocina durante aproximadamente 2-3 minutos hasta que estén rosadas y bien cocidas.","Añade las gulas a la sartén y cocina por un par de minutos, removiendo para mezclar los sabores.","En un bol aparte, bate los huevos con sal y pimienta al gusto hasta que estén bien mezclados.","Vierte los huevos batidos sobre la mezcla de gulas y gambas en la sartén, bajando el fuego a medio-bajo.","Revuelve suavemente con una espátula hasta que los huevos estén cocidos a tu gusto; no dejes que se sequen demasiado."]'::jsonb, 'Disfruta de un delicioso revuelto de gulas y gambas, una combinación perfecta de sabores del mar que te hará sentirte ligero y satisfecho. Ideal para un almuerzo nutritivo que no sacrifica el placer de comer bien.', '["Utiliza gambas frescas para un mejor sabor y textura.","No sobrecocines los huevos; deben quedar cremosos y jugosos.","Prueba a añadir un toque de salsa de soja para un sabor umami extra."]'::jsonb, '["Sustituye las gulas por surimi si prefieres una alternativa más económica.","Usa claras de huevo en lugar de huevos enteros para reducir las calorías.","Incorpora espinacas frescas o acelgas para aumentar el contenido de fibra."]'::jsonb, '["Las gulas son una excelente fuente de proteína baja en grasa.","Las gambas aportan ácidos grasos omega-3 que benefician la salud cardiovascular.","Los huevos son ricos en vitaminas y minerales esenciales como la vitamina D y el selenio."]'::jsonb, '["Este plato es bajo en calorías pero alto en proteínas, lo que ayuda a mantener la saciedad.","La combinación de ingredientes promueve un metabolismo saludable gracias a sus nutrientes.","El alto contenido de proteínas y fibra ayuda a reducir el apetito y evitar picoteos entre comidas."]'::jsonb),

--------------------------------------------------------------------------------
-- 21 CENAS
--------------------------------------------------------------------------------
(gen_random_uuid(), 'Salmón al horno con espárragos', 'Cena', '/images/r_cena_1.png', 350, 35, 10, 18, 25, '{"Principal":["4 filetes de salmón (150 g cada uno)","500 g de espárragos frescos","2 cucharadas de aceite de oliva","2 dientes de ajo picados","Sal y pimienta al gusto","1 limón (zumo y ralladura)"],"Opcional":["1 cucharadita de pimentón dulce","1 cucharada de eneldo fresco picado"]}'::jsonb, '["Precalienta el horno a 200°C (400°F).","Lava y corta los extremos duros de los espárragos, luego colócalos en una bandeja para hornear.","En un tazón pequeño, mezcla el aceite de oliva, el ajo picado, el zumo y la ralladura de limón, y sazona con sal y pimienta.","Coloca los filetes de salmón sobre los espárragos en la bandeja y vierte la mezcla de aceite de oliva por encima.","Si lo deseas, espolvorea el pimentón y el eneldo sobre el salmón y los espárragos para realzar el sabor.","Hornea durante 15-20 minutos, o hasta que el salmón esté cocido y los espárragos estén tiernos pero crujientes."]'::jsonb, 'Disfruta de la combinación perfecta entre el salmón tierno y los espárragos crujientes, una cena que no solo deleita el paladar, sino que también nutre el cuerpo.', '["Asegúrate de no sobrecocinar el salmón; debe desmenuzarse fácilmente con un tenedor.","Puedes marinar el salmón durante 30 minutos antes de cocinarlo para intensificar el sabor.","Utiliza papel de aluminio para cubrir la bandeja durante los primeros 10 minutos de cocción para mantener la humedad."]'::jsonb, '["Salmón por trucha o tilapia para una opción más ligera.","Espárragos por brócoli o judías verdes si no están disponibles.","Aceite de oliva por aceite de aguacate para un sabor más suave."]'::jsonb, '["El salmón es rico en ácidos grasos omega-3, que son beneficiosos para la salud del corazón.","Los espárragos son una excelente fuente de fibra, lo que ayuda a la digestión.","Esta receta es alta en proteínas, lo que favorece la saciedad."]'::jsonb, '["Bajo en calorías pero alto en nutrientes, lo que ayuda a mantener la saciedad sin exceder el consumo calórico.","Los ácidos grasos omega-3 pueden ayudar a reducir la inflamación y mejorar la salud metabólica.","La fibra de los espárragos contribuye a una digestión saludable y promueve una sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Sopa de verduras depurativa', 'Cena', '/images/r_cena_2.png', 180, 5, 25, 4, 30, '{"Principal":["2 zanahorias medianas, peladas y picadas","1 calabacín mediano, picado","1 pimiento rojo, picado","1 cebolla pequeña, picada","2 dientes de ajo, picados","1 litro de caldo de verduras bajo en sodio","200 g de espinacas frescas","1 cucharada de aceite de oliva","Sal y pimienta al gusto"],"Opcional":["1 ramita de tomillo fresco","1 hoja de laurel","Jugo de limón al gusto"]}'::jsonb, '["Calienta el aceite de oliva en una olla grande a fuego medio.","Añade la cebolla y el ajo, y sofríe durante 3-4 minutos hasta que estén tiernos y fragantes.","Incorpora las zanahorias, el calabacín y el pimiento rojo; cocina por otros 5 minutos, removiendo ocasionalmente.","Agrega el caldo de verduras, el tomillo y la hoja de laurel, y lleva a ebullición.","Reduce el fuego y deja que la sopa hierva a fuego lento durante 15 minutos, o hasta que las verduras estén tiernas.","Incorpora las espinacas y cocina por 2-3 minutos más. Retira la hoja de laurel y el tomillo antes de servir."]'::jsonb, 'Disfruta de una reconfortante sopa de verduras depurativa que no solo nutre tu cuerpo, sino que también revitaliza tu espíritu. Cada cucharada está llena de frescura y sabor, perfecta para una cena ligera y saludable.', '["Para un sabor más profundo, tuesta las verduras en la olla antes de añadir el caldo.","Ajusta las especias y hierbas a tu gusto para personalizar la sopa.","Si prefieres una textura más cremosa, puedes hacer puré una parte de la sopa con una batidora."]'::jsonb, '["Sustituye las espinacas por kale o acelgas.","Utiliza caldo de pollo en lugar de caldo de verduras para un sabor diferente.","Reemplaza el calabacín por apio o brócoli según tu preferencia."]'::jsonb, '["Rica en vitaminas y minerales gracias a la variedad de verduras.","Bajo contenido calórico, ideal para una cena ligera.","Fuente de fibra, que ayuda a la digestión y promueve la saciedad."]'::jsonb, '["Bajo en calorías, lo que permite un déficit calórico en la cena.","La alta cantidad de fibra ayuda a controlar el apetito y reduce los antojos.","Las verduras son nutritivas y saciantes, lo que puede prevenir el picoteo nocturno."]'::jsonb),
(gen_random_uuid(), 'Tortilla francesa con champiñones', 'Cena', '/images/r_cena_3.png', 260, 16, 5, 18, 10, '{"Principal":["4 huevos","200 g de champiñones frescos","1 cucharada de aceite de oliva","Sal al gusto","Pimienta negra al gusto"],"Opcional":["Un puñado de perejil fresco picado","Queso rallado bajo en grasa al gusto"]}'::jsonb, '["Lava los champiñones bajo agua fría y sécalos con un paño de cocina. Luego, corta los champiñones en láminas finas.","En una sartén antiadherente, calienta el aceite de oliva a fuego medio. Añade los champiñones y sofríelos durante unos 5 minutos hasta que estén dorados y tiernos.","Mientras se cocinan los champiñones, bate los huevos en un bol grande, añadiendo sal y pimienta al gusto.","Una vez que los champiñones estén listos, agrégales a los huevos batidos y mezcla bien para que se integren.","Vierte la mezcla en la sartén y cocina a fuego medio-bajo durante aproximadamente 3-4 minutos o hasta que los bordes de la tortilla comiencen a cuajar.","Con ayuda de una espátula, dobla la tortilla por la mitad y cocina durante 1-2 minutos más. Sirve caliente y, si lo deseas, añade perejil picado o queso rallado por encima."]'::jsonb, 'Disfruta de una deliciosa y ligera tortilla francesa con champiñones, perfecta para una cena nutritiva que satisface sin pesar. Esta receta es un abrazo de sabor y salud en cada bocado.', '["Utiliza huevos frescos para obtener un mejor sabor y textura en la tortilla.","Asegúrate de que la sartén esté bien caliente antes de añadir la mezcla de huevos para evitar que se pegue.","Si prefieres una tortilla más esponjosa, puedes añadir un chorrito de leche a los huevos batidos."]'::jsonb, '["Utiliza claras de huevo en lugar de huevos enteros para reducir las calorías y grasas.","Sustituye los champiñones por espinacas o pimientos para variar el sabor y los nutrientes.","Prueba con aceite de aguacate en lugar de aceite de oliva para un perfil de grasas diferente."]'::jsonb, '["Los huevos son una excelente fuente de proteínas de alta calidad, esenciales para la reparación muscular.","Los champiñones son bajos en calorías y ricos en antioxidantes, promoviendo la salud celular.","Este plato es rico en vitaminas del complejo B, que son cruciales para el metabolismo energético."]'::jsonb, '["Es bajo en calorías y alto en proteínas, lo que ayuda a sentirte saciado por más tiempo.","Los ingredientes son ricos en nutrientes, lo que permite obtener la energía necesaria sin exceso de calorías vacías.","Su preparación rápida y sencilla facilita la inclusión de comidas saludables en tu rutina diaria."]'::jsonb),
(gen_random_uuid(), 'Ensalada Caprese', 'Cena', '/images/r_cena_4.png', 310, 15, 10, 22, 5, '{"Principal":["3 tomates medianos, maduros y jugosos","200 g de mozzarella fresca","1 manojo de albahaca fresca","3 cucharadas de aceite de oliva virgen extra","Sal al gusto","Pimienta negra al gusto"],"Opcional":["Balsámico en reducción para decorar","Nueces o piñones tostados"]}'::jsonb, '["Lava bien los tomates bajo agua corriente y sécalos con un paño limpio.","Corta los tomates en rodajas de aproximadamente 1 cm de grosor.","Corta la mozzarella en rodajas del mismo grosor que los tomates.","En un plato grande, alterna las rodajas de tomate y mozzarella, formando un patrón atractivo.","Lava las hojas de albahaca y sécalas suavemente, luego colócalas entre las capas de tomate y mozzarella.","Rocía la ensalada con el aceite de oliva, luego añade sal y pimienta al gusto. Si lo deseas, agrega un chorrito de balsámico en reducción por encima antes de servir."]'::jsonb, 'Disfruta de una vibrante Ensalada Caprese, donde la frescura del tomate se une con la cremosidad de la mozzarella y el aroma del albahaca. Un plato ligero y lleno de sabor que hará que tu cena sea un verdadero deleite.', '["Utiliza tomates de temporada para obtener el mejor sabor y frescura.","Asegúrate de que la mozzarella esté a temperatura ambiente para que se aprecie mejor su textura y sabor.","No escatimes en el aceite de oliva, es clave para realzar los sabores de la ensalada."]'::jsonb, '["Usa queso burrata en lugar de mozzarella para una textura aún más cremosa.","Sustituye el aceite de oliva por aceite de aguacate para un sabor diferente y beneficios adicionales.","Prueba con albahaca seca si no tienes albahaca fresca a mano."]'::jsonb, '["Los tomates son ricos en licopeno, un antioxidante que ayuda a proteger el corazón.","La mozzarella aporta proteínas y calcio, esenciales para la salud ósea.","El aceite de oliva virgen extra contiene grasas saludables que benefician el sistema cardiovascular."]'::jsonb, '["Bajo en calorías, lo que permite disfrutar de una cena ligera sin comprometer la saciedad.","Rico en fibra, gracias a los tomates y la albahaca, que ayuda a mantener la sensación de plenitud.","Los ácidos grasos saludables del aceite de oliva pueden ayudar a regular el apetito."]'::jsonb),
(gen_random_uuid(), 'Calabacines rellenos de atún', 'Cena', '/images/r_cena_5.png', 280, 25, 15, 10, 30, '{"Principal":["2 calabacines medianos","1 lata de atún en agua (aproximadamente 150g)","1/2 cebolla picada","1/2 pimiento rojo picado","2 cucharadas de aceite de oliva","1/4 taza de queso rallado bajo en grasa","1 cucharadita de orégano seco","Sal y pimienta al gusto"],"Opcional":["1/4 taza de aceitunas negras picadas","1 cucharada de albahaca fresca picada"]}'::jsonb, '["Precalienta el horno a 180°C (350°F).","Lava los calabacines y córtalos por la mitad a lo largo. Con una cuchara, saca la pulpa del centro, dejando un borde de aproximadamente 1 cm.","En una sartén, calienta el aceite de oliva a fuego medio. Agrega la cebolla y el pimiento rojo, y sofríe hasta que estén tiernos, unos 5 minutos.","Añade la pulpa del calabacín, el atún escurrido, el orégano, sal y pimienta. Cocina por 3-4 minutos, mezclando bien todos los ingredientes.","Rellena las mitades de calabacín con la mezcla de atún y espolvorea el queso rallado por encima.","Coloca los calabacines rellenos en una bandeja para hornear y hornea durante 20-25 minutos, o hasta que estén tiernos y el queso esté dorado."]'::jsonb, 'Disfruta de unos calabacines rellenos de atún, una cena ligera y deliciosa que combina sabores frescos y nutritivos. Perfectos para una velada saludable y satisfactoria.', '["Para un sabor más intenso, puedes asar los calabacines antes de rellenarlos.","Utiliza atún en aceite de oliva para un sabor más rico, pero recuerda escurrirlo bien.","Experimenta con diferentes hierbas frescas para personalizar el sabor de tu relleno."]'::jsonb, '["Sustituye el atún por pollo desmenuzado para una opción diferente.","Utiliza calabacines amarillos en lugar de verdes para un toque colorido.","Reemplaza el queso bajo en grasa por queso feta desmenuzado para un sabor más fuerte."]'::jsonb, '["Los calabacines son ricos en fibra, lo que ayuda a la digestión.","El atún es una excelente fuente de proteínas y ácidos grasos omega-3.","Esta receta es baja en carbohidratos, ideal para dietas equilibradas."]'::jsonb, '["Bajo en calorías, lo que ayuda a mantener un déficit calórico.","Alto contenido de proteínas que promueve la saciedad y reduce los antojos.","La fibra de los calabacines ayuda a la sensación de plenitud, evitando el picoteo."]'::jsonb),
(gen_random_uuid(), 'Pechuga a la plancha con pepino', 'Cena', '/images/r_cena_6.png', 240, 30, 5, 8, 10, '{"Principal":["200g de pechuga de pollo","1 cucharada de aceite de oliva","Sal al gusto","Pimienta negra al gusto"],"Opcional":["1 pepino mediano","Jugo de medio limón","1 cucharada de eneldo fresco picado"]}'::jsonb, '["Lava y corta el pepino en rodajas finas, luego colócalo en un tazón y añade el jugo de limón y el eneldo. Mezcla bien y reserva.","Condimenta la pechuga de pollo con sal y pimienta al gusto. Asegúrate de cubrirla uniformemente.","Calienta una sartén antiadherente a fuego medio-alto y añade el aceite de oliva.","Cuando el aceite esté caliente, coloca la pechuga de pollo en la sartén y cocina durante 6-7 minutos por un lado.","Voltea la pechuga y cocina por otros 5-6 minutos o hasta que esté dorada y cocida por completo.","Retira la pechuga de pollo de la sartén y déjala reposar durante un par de minutos antes de cortarla en tiras y servirla con el pepino."]'::jsonb, 'Disfruta de una cena ligera y llena de sabor con esta deliciosa pechuga a la plancha acompañada de refrescantes rodajas de pepino. Es una opción perfecta para terminar el día sintiéndote satisfecho y saludable.', '["Para obtener una pechuga de pollo más jugosa, marínala en jugo de limón y hierbas durante 30 minutos antes de cocinar.","Utiliza un termómetro de cocina para asegurarte de que la pechuga de pollo alcance una temperatura interna de 75°C.","Cocina a fuego medio-alto para conseguir un dorado perfecto en la pechuga."]'::jsonb, '["Sustituye el pollo por pavo para una opción baja en grasas.","Utiliza aceite de aguacate en lugar de aceite de oliva para un sabor diferente y beneficios adicionales.","Cambia el pepino por calabacín para una alternativa con un sabor suave y textura crujiente."]'::jsonb, '["La pechuga de pollo es una excelente fuente de proteínas magras, esencial para el desarrollo muscular.","El pepino es bajo en calorías y rico en agua, lo que ayuda a la hidratación.","El eneldo contiene antioxidantes que pueden ayudar a reducir la inflamación."]'::jsonb, '["Alta en proteínas, esta receta puede ayudar a aumentar la saciedad, reduciendo el hambre entre comidas.","La baja cantidad de calorías en el pepino permite disfrutar de una cena abundante sin comprometer la ingesta calórica.","Los alimentos ricos en agua como el pepino ayudan a mantenerte hidratado, lo que es esencial para la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Crema de calabaza', 'Cena', '/images/r_cena_7.png', 200, 4, 30, 6, 25, '{"Principal":["500g de calabaza pelada y cortada en cubos","1 cebolla mediana picada","2 dientes de ajo picados","750ml de caldo de verduras","200ml de leche de coco","2 cucharadas de aceite de oliva","Sal al gusto","Pimienta al gusto","1 cucharadita de comino en polvo"],"Opcional":["Semillas de calabaza para decorar","Un chorrito de aceite de trufa","Cilantro fresco picado"]}'::jsonb, '["En una olla grande, calienta el aceite de oliva a fuego medio y añade la cebolla picada. Sofríe hasta que esté transparente, aproximadamente 5 minutos.","Agrega el ajo picado y sofríe por 1-2 minutos más, cuidando que no se queme.","Incorpora los cubos de calabaza y el comino, mezclando bien para que se integren los sabores. Cocina durante 5 minutos.","Vierte el caldo de verduras y lleva a ebullición. Reduce el fuego y deja cocinar a fuego lento durante 20 minutos o hasta que la calabaza esté tierna.","Retira del fuego y utiliza una batidora de mano para hacer puré la mezcla hasta obtener una textura suave y cremosa.","Añade la leche de coco, mezcla bien y ajusta la sal y pimienta al gusto. Calienta nuevamente si es necesario antes de servir."]'::jsonb, 'Disfruta de una reconfortante crema de calabaza que calienta el alma y nutre el cuerpo, ideal para una cena ligera y nutritiva.', '["Para un sabor más profundo, asar la calabaza en el horno antes de añadirla a la olla.","Utiliza un colador para eliminar cualquier grumo si prefieres una crema más lisa.","No dudes en ajustar la consistencia de la crema añadiendo más caldo si la prefieres más líquida."]'::jsonb, '["Sustituye la leche de coco por leche de almendras para una opción más ligera.","Utiliza calabacín en lugar de calabaza para una crema con un sabor más suave.","Reemplaza el comino por curry en polvo para un toque diferente."]'::jsonb, '["La calabaza es rica en antioxidantes y vitaminas A y C, que apoyan la salud ocular y el sistema inmunológico.","La leche de coco proporciona grasas saludables que promueven la saciedad.","El ajo tiene propiedades antiinflamatorias y puede ayudar a reducir la presión arterial."]'::jsonb, '["La crema de calabaza es baja en calorías, lo que permite disfrutar de una comida abundante sin comprometer la ingesta calórica.","Las fibras de la calabaza favorecen la digestión y ayudan a mantener la sensación de saciedad por más tiempo.","El uso de ingredientes naturales y saludables reduce la probabilidad de antojos entre comidas."]'::jsonb),
(gen_random_uuid(), 'Espaguetis de calabacín con pavo', 'Cena', '/images/r_cena_8.png', 270, 25, 10, 12, 15, '{"Principal":["2 calabacines medianos","300 g de pechuga de pavo molida","2 cucharadas de aceite de oliva","2 dientes de ajo, picados","1/2 cebolla, picada","400 g de tomates triturados","Sal y pimienta al gusto","1 cucharadita de orégano seco","1 cucharadita de albahaca seca"],"Opcional":["Queso parmesano rallado al gusto","Perejil fresco para decorar"]}'::jsonb, '["Lava los calabacines y utiliza un espiralizador para convertirlos en espaguetis. Reserva.","En una sartén grande, calienta el aceite de oliva a fuego medio y añade la cebolla y el ajo. Sofríe hasta que estén dorados y fragantes.","Agrega la pechuga de pavo molida y cocina hasta que esté bien dorada, desmenuzando la carne con una cuchara de madera.","Incorpora los tomates triturados, el orégano y la albahaca. Cocina a fuego lento durante unos 10 minutos, permitiendo que los sabores se mezclen.","Mientras la salsa se cocina, en otra sartén, añade un poco de aceite de oliva y saltea los espaguetis de calabacín durante 2-3 minutos hasta que estén tiernos pero aún crujientes.","Sirve los espaguetis de calabacín en platos y vierte la salsa de pavo por encima. Decora con queso parmesano y perejil fresco si lo deseas."]'::jsonb, 'Disfruta de unos deliciosos espaguetis de calabacín con pavo, una cena ligera y nutritiva que hará que tu paladar se deleite sin remordimientos. Perfecta para mantenerte en forma y satisfecho al mismo tiempo.', '["No sobrecocines los espaguetis de calabacín para mantener su textura crujiente.","Puedes añadir verduras como pimientos o espinacas a la mezcla de pavo para aumentar el valor nutricional.","Utiliza hierbas frescas si las tienes disponibles para un sabor más intenso."]'::jsonb, '["Sustituye el pavo por pechuga de pollo molida o tofu para una opción vegetariana.","Usa salsa de tomate casera en lugar de tomates triturados enlatados para un mejor control de los ingredientes.","Reemplaza el aceite de oliva por aceite de aguacate si buscas un sabor más suave."]'::jsonb, '["El calabacín es bajo en calorías y rico en fibra, lo que ayuda a la digestión.","El pavo es una excelente fuente de proteínas magras, esencial para el desarrollo muscular.","Los tomates son ricos en antioxidantes, como el licopeno, que benefician la salud cardiovascular."]'::jsonb, '["Esta receta es baja en carbohidratos, lo que ayuda a controlar el índice glucémico.","La alta cantidad de fibra en el calabacín promueve la saciedad, reduciendo la necesidad de comer en exceso.","El pavo magro proporciona proteínas que ayudan a mantener la masa muscular durante la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Tartar de salmón y aguacate', 'Cena', '/images/r_cena_9.png', 360, 25, 5, 25, 15, '{"Principal":["200g de salmón fresco, sin piel y picado en cubos pequeños","1 aguacate maduro, picado en cubos","1 cucharada de cebolla morada, finamente picada","1 cucharada de cilantro fresco, picado","1 cucharadita de salsa de soja baja en sodio","1 cucharadita de jugo de limón","Sal y pimienta al gusto"],"Opcional":["1 cucharadita de aceite de sésamo","Semillas de sésamo tostadas para decorar","Rodajas de pepino para servir"]}'::jsonb, '["Comienza asegurándote de que el salmón esté fresco y de calidad. Corta el salmón en cubos pequeños y colócalo en un tazón.","Agrega el aguacate picado al tazón con el salmón, teniendo cuidado de no aplastarlo.","Incorpora la cebolla morada y el cilantro fresco, mezclando suavemente para que todos los ingredientes se integren.","Añade la salsa de soja y el jugo de limón, mezclando con cuidado para no dañar el aguacate.","Sazona con sal y pimienta al gusto, ajustando según tus preferencias personales.","Sirve el tartar en un plato, decorando con semillas de sésamo tostadas y acompañando con rodajas de pepino si lo deseas."]'::jsonb, 'Disfruta de un delicioso tartar de salmón y aguacate, una fusión perfecta de frescura y sabor que deleitará tu paladar mientras cuidas de tu bienestar.', '["Utiliza un cuchillo muy afilado para cortar el salmón y el aguacate, esto garantiza cortes limpios y evita que los ingredientes se aplasten.","Refrigera el salmón antes de prepararlo para que sea más fácil de manejar y cortar.","Si prefieres un sabor más intenso, añade un poco de salsa picante o wasabi a la mezcla."]'::jsonb, '["Salmón por atún fresco para un tartar diferente y delicioso.","Aguacate por mango para un toque dulce y tropical.","Cebolla morada por cebollino para un sabor más suave."]'::jsonb, '["El salmón es una excelente fuente de ácidos grasos omega-3, que son beneficiosos para la salud del corazón.","El aguacate aporta grasas saludables y fibra, esenciales para una digestión saludable.","El cilantro es rico en antioxidantes y puede ayudar a la desintoxicación del cuerpo."]'::jsonb, '["Bajo en calorías y rico en proteínas, el tartar de salmón ayuda a mantener la saciedad sin añadir muchas calorías.","La combinación de grasas saludables del aguacate y el salmón puede ayudar a regular el apetito.","La alta cantidad de fibra del aguacate y los vegetales opcionales puede favorecer la digestión y el control del peso."]'::jsonb),
(gen_random_uuid(), 'Ensalada de espinacas y queso fresco', 'Cena', '/images/r_cena_10.png', 230, 15, 5, 15, 5, '{"Principal":["150 g de espinacas frescas","100 g de queso fresco","1 tomate grande","1/2 pepino","30 g de nueces","2 cucharadas de aceite de oliva","1 cucharada de vinagre balsámico","Sal al gusto","Pimienta al gusto"],"Opcional":["1/4 de cebolla morada","1 aguacate pequeño","Semillas de chía para decorar"]}'::jsonb, '["Lava bien las espinacas bajo agua fría y escúrrelas en un colador.","Corta el queso fresco en cubos pequeños y reserva.","Pica el tomate y el pepino en cubos, y si decides usar cebolla morada, córtala en rodajas finas.","En un tazón grande, mezcla las espinacas, el tomate, el pepino y la cebolla si la usas.","En un tazón pequeño, combina el aceite de oliva, el vinagre balsámico, sal y pimienta, y mezcla bien.","Vierte el aderezo sobre la ensalada, añade los cubos de queso fresco y las nueces, y mezcla suavemente para combinar los ingredientes."]'::jsonb, 'Disfruta de una explosión de frescura y sabor con esta ensalada de espinacas y queso fresco, perfecta para una cena ligera y nutritiva que te dejará satisfecho y lleno de energía.', '["Para un sabor más intenso, tuesta ligeramente las nueces antes de añadirlas a la ensalada.","Asegúrate de que las espinacas estén bien secas para evitar que la ensalada se empape.","Puedes preparar el aderezo con anticipación y guardarlo en el refrigerador para ahorrar tiempo."]'::jsonb, '["Puedes usar queso feta en lugar de queso fresco para un sabor más fuerte.","Sustituye las nueces por almendras o semillas de girasol para variar la textura.","Si no tienes vinagre balsámico, utiliza jugo de limón como alternativa."]'::jsonb, '["Las espinacas son ricas en hierro y fibra, lo que favorece la salud digestiva.","El queso fresco aporta calcio, esencial para la salud ósea.","Las nueces son una fuente de grasas saludables que ayudan a mantener el corazón sano."]'::jsonb, '["Esta ensalada es baja en calorías, lo que la convierte en una opción ideal para cenas ligeras.","La fibra de las espinacas y el pepino ayuda a sentirse saciado por más tiempo.","Las grasas saludables de las nueces contribuyen a un metabolismo eficiente, lo que puede ayudar en la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Hamburguesa de pollo sin pan', 'Cena', '/images/r_cena_11.png', 290, 35, 10, 12, 15, '{"Principal":["500g de pechuga de pollo picada","1 huevo","50g de cebolla finamente picada","2 dientes de ajo picados","1 cucharadita de mostaza","1 cucharadita de pimentón dulce","Sal y pimienta al gusto","Hojas de lechuga para servir"],"Opcional":["Rodajas de tomate","Rodajas de aguacate","Salsa de yogur o mayonesa ligera"]}'::jsonb, '["En un bol grande, mezcla la pechuga de pollo picada con el huevo, la cebolla, el ajo, la mostaza, el pimentón, la sal y la pimienta hasta obtener una mezcla homogénea.","Divide la mezcla en cuatro porciones y forma las hamburguesas con las manos, asegurándote de que queden bien compactas.","Calienta una sartén grande a fuego medio-alto y añade un poco de aceite de oliva.","Coloca las hamburguesas en la sartén caliente y cocina durante 5-6 minutos por cada lado, o hasta que estén bien doradas y cocidas por dentro.","Retira las hamburguesas de la sartén y deja reposar durante un par de minutos.","Sirve las hamburguesas sobre hojas de lechuga y añade las rodajas de tomate, aguacate y salsa al gusto."]'::jsonb, 'Disfruta de esta deliciosa hamburguesa de pollo sin pan, una opción ligera y llena de sabor que hará que tus cenas sean inolvidables. Perfecta para cuidarte mientras te das un capricho saludable.', '["Asegúrate de que la pechuga de pollo esté bien picada para que las hamburguesas tengan una textura uniforme.","No sobrecocines las hamburguesas para mantener su jugosidad; un termómetro de cocina puede ayudarte a verificar que alcancen 75°C en el centro.","Para un sabor extra, marina el pollo con especias o hierbas un par de horas antes de cocinar."]'::jsonb, '["Sustituye la pechuga de pollo por pavo molido para una opción más magra.","Usa espinacas o rúcula en lugar de lechuga para un aporte extra de nutrientes.","Cambia la mostaza por salsa de soja baja en sodio para un sabor diferente."]'::jsonb, '["Rico en proteínas magras que ayudan a la reparación muscular.","Bajo en carbohidratos, ideal para dietas cetogénicas o bajas en carbohidratos.","Incorpora vegetales frescos que aportan vitaminas y minerales esenciales."]'::jsonb, '["Al ser bajo en calorías, favorece el control del peso sin sacrificar el sabor.","La alta cantidad de proteínas ayuda a aumentar la saciedad, reduciendo el apetito.","Sustituir el pan por verduras incrementa el consumo de fibra, lo que mejora la digestión y la sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Merluza a la romana al horno', 'Cena', '/images/r_cena_12.png', 280, 25, 15, 10, 20, '{"Principal":["4 filetes de merluza (aproximadamente 150g cada uno)","1 taza de pan rallado integral","1/2 taza de harina de avena","2 huevos grandes","1 cucharadita de pimentón dulce","Sal al gusto","Pimienta al gusto"],"Opcional":["2 cucharadas de aceite de oliva virgen extra","Rodajas de limón para servir","Perejil fresco picado para decorar"]}'::jsonb, '["Precalienta el horno a 200°C (390°F) y prepara una bandeja de horno forrándola con papel vegetal.","En un plato hondo, bate los huevos junto con el pimentón, sal y pimienta hasta que estén bien mezclados.","En un segundo plato, coloca la harina de avena y en un tercero, el pan rallado integral.","Toma cada filete de merluza, pásalo primero por la harina, luego por la mezcla de huevo y finalmente cúbrelo bien con el pan rallado.","Coloca los filetes empanizados en la bandeja de horno y rocía con un poco de aceite de oliva para darle un toque extra de sabor y crujiente.","Hornea durante 15-20 minutos o hasta que la merluza esté dorada y cocida por dentro, sirviendo caliente con rodajas de limón y perejil fresco."]'::jsonb, 'Disfruta de una merluza a la romana al horno, crujiente por fuera y suave por dentro, que te hará sentir como si estuvieras en un restaurante gourmet desde la comodidad de tu hogar.', '["Para un empanizado más crujiente, deja reposar los filetes empanizados en la nevera durante 15 minutos antes de hornear.","Usa un termómetro de cocina para asegurarte de que la merluza alcance una temperatura interna de 63°C (145°F).","Acompaña el plato con una ensalada fresca para equilibrar la comida y añadir más nutrientes."]'::jsonb, '["Puedes usar filetes de otro pescado blanco como el bacalao.","Sustituye el pan rallado integral por avena molida para una opción sin gluten.","Reemplaza los huevos por un ''huevo'' de linaza (1 cucharada de linaza molida + 3 cucharadas de agua) para una versión vegana."]'::jsonb, '["La merluza es rica en proteínas de alta calidad y baja en grasas saturadas.","Contiene ácidos grasos omega-3 que son beneficiosos para la salud cardiovascular.","El pan integral aporta fibra, lo que ayuda a la digestión y promueve la saciedad."]'::jsonb, '["La merluza es baja en calorías, ideal para dietas de control de peso.","El alto contenido de proteínas ayuda a mantener la masa muscular durante la pérdida de peso.","La fibra del pan integral y la harina de avena ayuda a sentirte lleno por más tiempo, reduciendo la ingesta calórica total."]'::jsonb),
(gen_random_uuid(), 'Gazpacho andaluz', 'Cena', '/images/r_cena_13.png', 180, 3, 20, 10, 10, '{"Principal":["1 kg de tomates maduros","1 pimiento verde","1 pepino","1 cebolla pequeña","2 dientes de ajo","50 ml de aceite de oliva virgen extra","30 ml de vinagre de vino","Sal al gusto","Agua fría al gusto"],"Opcional":["Pan del día anterior (50 g) para espesar","Pimiento rojo para decorar","Cebollino picado para decorar"]}'::jsonb, '["Lava bien los tomates, pimientos y pepinos bajo agua fría para eliminar cualquier residuo.","Corta los tomates, el pimiento verde, el pepino y la cebolla en trozos grandes y colócalos en una batidora de alta potencia.","Añade los dientes de ajo pelados, el aceite de oliva, el vinagre y una pizca de sal a la mezcla.","Si decides utilizar pan, añádelo también en este momento para conseguir una textura más cremosa.","Bate todos los ingredientes a alta velocidad hasta obtener una mezcla homogénea y suave, ajustando la consistencia con agua fría si es necesario.","Prueba y ajusta la sal y el vinagre según tu gusto antes de refrigerar el gazpacho durante al menos 30 minutos para que los sabores se integren."]'::jsonb, 'Disfruta de un refrescante gazpacho andaluz, una explosión de sabores mediterráneos que te transportará a las calurosas tierras del sur de España. Perfecto para una cena ligera y nutritiva que deleitará tus sentidos.', '["Para un sabor más intenso, deja reposar el gazpacho en la nevera durante varias horas antes de servir.","Utiliza tomates de temporada para obtener el mejor sabor y color en tu gazpacho.","Si prefieres una textura más fina, cuela la mezcla a través de un colador antes de servir."]'::jsonb, '["El aceite de oliva puede ser reemplazado por aceite de aguacate para una opción más ligera.","En lugar de vinagre de vino, puedes usar jugo de limón fresco para un toque cítrico.","Si no tienes cebolla, el puerro puede ser una buena alternativa para añadir dulzura."]'::jsonb, '["Rico en antioxidantes gracias a los tomates, que ayudan a combatir el estrés oxidativo.","Alto en fibra, lo que favorece la salud digestiva y la saciedad.","Bajo en calorías, ideal para mantener una dieta equilibrada."]'::jsonb, '["El gazpacho es bajo en calorías y alto en agua, lo que ayuda a mantenerte hidratado y a sentirte lleno.","La fibra de los vegetales ayuda a regular el apetito, reduciendo la ingesta de calorías a lo largo del día.","Su bajo contenido calórico permite disfrutar de una porción generosa sin comprometer tus objetivos de pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Tortilla de calabacín', 'Cena', '/images/r_cena_14.png', 250, 15, 8, 16, 20, '{"Principal":["2 calabacines medianos, rallados","4 huevos","1 cebolla pequeña, picada","2 cucharadas de aceite de oliva","Sal al gusto","Pimienta al gusto"],"Opcional":["30g de queso feta desmenuzado","1 cucharada de perejil fresco picado","Pimiento rojo en tiras para decorar"]}'::jsonb, '["Lava los calabacines y rálalos finamente. Colócalos en un colador, espolvorea con un poco de sal y déjalos reposar durante 15 minutos para que suelten el exceso de agua.","Mientras tanto, en una sartén grande, calienta el aceite de oliva a fuego medio y añade la cebolla picada. Sofríe hasta que esté dorada y suave, aproximadamente 5 minutos.","Exprime los calabacines con las manos para eliminar el exceso de agua y agrégales a la sartén con la cebolla. Cocina durante 5-7 minutos, removiendo ocasionalmente.","En un bol aparte, bate los huevos y sazona con sal y pimienta. Agrega los calabacines y cebolla cocidos al bol con los huevos batidos y mezcla bien.","Vierte la mezcla en la sartén, asegurándote de que se distribuya uniformemente. Cocina a fuego medio-bajo durante unos 8-10 minutos, o hasta que la base esté dorada.","Con ayuda de un plato, da la vuelta a la tortilla y cocina por el otro lado durante 5-7 minutos más. Retira del fuego y sirve caliente, decorando con perejil y pimiento si lo deseas."]'::jsonb, 'Disfruta de una deliciosa tortilla de calabacín, ligera y llena de sabor, perfecta para una cena nutritiva que te dejará satisfecho sin pesadez.', '["Utiliza una sartén antiadherente para evitar que la tortilla se pegue y facilitar el volteo.","Si prefieres una textura más suave, puedes cocinar la tortilla a fuego más bajo durante más tiempo.","Experimenta con hierbas frescas como albahaca o orégano para darle un giro diferente a la receta."]'::jsonb, '["Sustituye los huevos por una mezcla de 1/2 taza de puré de tofu y 2 cucharadas de harina de garbanzo para una versión vegana.","Cambia el aceite de oliva por aceite de aguacate para un sabor más suave y un perfil de grasas más saludable.","Usa calabacín amarillo en lugar de verde para un color vibrante y un sabor ligeramente diferente."]'::jsonb, '["El calabacín es bajo en calorías y alto en agua, lo que ayuda a mantener la hidratación.","Los huevos son una excelente fuente de proteínas de alta calidad y nutrientes esenciales como la vitamina D.","Esta receta es rica en fibra, lo que favorece la salud digestiva y la sensación de saciedad."]'::jsonb, '["Bajo en calorías, lo que permite disfrutar de una comida abundante sin exceder el límite calórico diario.","La alta cantidad de fibra en el calabacín ayuda a mantener la sensación de saciedad por más tiempo.","Las proteínas en los huevos ayudan a conservar la masa muscular durante la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Brochetas de pavo y verduras', 'Cena', '/images/r_cena_15.png', 260, 30, 10, 8, 20, '{"Principal":["500g de pechuga de pavo, cortada en cubos","1 pimiento rojo, cortado en trozos","1 pimiento verde, cortado en trozos","1 calabacín, cortado en rodajas","200g de champiñones, enteros o cortados por la mitad","2 cucharadas de aceite de oliva","1 cucharadita de pimentón dulce","Sal y pimienta al gusto"],"Opcional":["Palitos de brocheta (de madera o metal)","Zumo de limón para marinar","Hierbas frescas como orégano o albahaca para decorar"]}'::jsonb, '["En un tazón grande, mezcla los cubos de pavo con el aceite de oliva, pimentón, sal y pimienta. Deja marinar durante al menos 30 minutos.","Mientras el pavo marina, prepara las verduras cortándolas en tamaños similares para asegurar una cocción uniforme.","Precalienta la parrilla o sartén a fuego medio-alto.","Ensarta los cubos de pavo y las verduras en los palitos de brocheta de manera alternada.","Coloca las brochetas en la parrilla caliente y cocina durante aproximadamente 10-12 minutos, girándolas ocasionalmente hasta que el pavo esté bien cocido y las verduras estén tiernas.","Retira las brochetas de la parrilla y deja reposar durante unos minutos antes de servir. Puedes rociar con un poco de zumo de limón y decorar con hierbas frescas."]'::jsonb, 'Disfruta de estas deliciosas brochetas de pavo y verduras, una opción ligera y llena de sabor que te hará sentir bien después de una larga jornada. Perfectas para una cena nutritiva y equilibrada.', '["Si usas palitos de madera, remójalos en agua durante 30 minutos antes de usarlos para evitar que se quemen en la parrilla.","Corta las verduras en tamaños similares para garantizar que se cocinen al mismo tiempo que el pavo.","No sobrecargues las brochetas; deja espacio entre los ingredientes para permitir una mejor circulación del calor."]'::jsonb, '["Puedes reemplazar el pavo por pechuga de pollo para una opción diferente.","Sustituye las verduras por tus favoritas, como cebolla, berenjena o espárragos.","Usa salsa de soja baja en sodio en lugar de sal para un toque asiático."]'::jsonb, '["El pavo es una excelente fuente de proteínas magras, lo que ayuda a la construcción y reparación muscular.","Las verduras aportan fibra, vitaminas y minerales esenciales que contribuyen a una dieta equilibrada.","El aceite de oliva es rico en grasas saludables que benefician la salud cardiovascular."]'::jsonb, '["Bajo en calorías y alto en proteínas, el pavo ayuda a mantener la saciedad y reduce el hambre.","Las verduras son bajas en calorías y ricas en fibra, lo que ayuda a controlar el peso.","Cocinar a la parrilla en lugar de freír reduce la cantidad de grasas añadidas, lo que ayuda a mantener una dieta más ligera."]'::jsonb),
(gen_random_uuid(), 'Ceviche de pescado blanco', 'Cena', '/images/r_cena_16.png', 220, 30, 10, 5, 20, '{"Principal":["300g de filete de pescado blanco (ej. mero, tilapia)","1/2 taza de jugo de limón fresco","1/4 taza de cebolla morada, finamente picada","1 tomate maduro, sin semillas y picado en cubos","1/2 aguacate, cortado en cubos","1/4 taza de cilantro fresco, picado","1 chile serrano, finamente picado (opcional)","Sal al gusto"],"Opcional":["Tostadas de maíz para acompañar","Rodajas de pepino como guarnición"]}'::jsonb, '["Corta el filete de pescado en cubos pequeños y colócalos en un tazón de vidrio.","Vierte el jugo de limón sobre el pescado, asegurándote de que esté completamente cubierto. Deja marinar en refrigeración durante 15-20 minutos.","Mientras el pescado se marina, pica finamente la cebolla morada, el tomate, el cilantro y el chile serrano si decides usarlo.","Una vez que el pescado ha cambiado de color, escúrrelo ligeramente y añade la cebolla, el tomate, el aguacate, el cilantro y el chile al tazón.","Mezcla suavemente todos los ingredientes para combinar, y añade sal al gusto.","Sirve el ceviche frío, acompañado de tostadas de maíz o rodajas de pepino."]'::jsonb, 'Disfruta de un ceviche de pescado blanco fresco y vibrante, lleno de sabores exóticos que despiertan tus sentidos y aportan frescura a tu cena.', '["Usa pescado muy fresco para garantizar el mejor sabor y textura en tu ceviche.","Deja marinar el pescado el tiempo suficiente para que se cocine en el jugo de limón, pero no demasiado tiempo para evitar que se vuelva gomoso.","Puedes ajustar la cantidad de chile según tu tolerancia al picante; siempre es mejor empezar con poco y añadir más si es necesario."]'::jsonb, '["Puedes sustituir el pescado blanco por camarones o pulpo si prefieres una variación de mariscos.","Utiliza jugo de lima en lugar de limón para un sabor más tropical.","El aguacate puede ser reemplazado por mango para un toque dulce."]'::jsonb, '["El pescado blanco es una excelente fuente de proteínas magras y ácidos grasos omega-3, que son beneficiosos para la salud cardiovascular.","El aguacate aporta grasas saludables y fibra, promoviendo una buena digestión.","El cilantro y los vegetales aportan antioxidantes y vitaminas esenciales."]'::jsonb, '["El ceviche es bajo en calorías y alto en proteínas, lo que ayuda a mantenerte saciado por más tiempo.","La inclusión de vegetales frescos proporciona fibra, que es clave para una buena digestión y control del apetito.","El alto contenido de agua en los ingredientes ayuda a la hidratación y puede contribuir a una sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Guisantes con jamón', 'Cena', '/images/r_cena_17.png', 280, 18, 25, 10, 15, '{"Principal":["300g de guisantes frescos o congelados","150g de jamón serrano en dados","1 cucharada de aceite de oliva","1 diente de ajo picado","1 cebolla pequeña picada"],"Opcional":["Perejil fresco picado para decorar","Pimienta negra al gusto"]}'::jsonb, '["En una sartén grande, calienta el aceite de oliva a fuego medio y añade la cebolla picada. Sofríe hasta que esté transparente.","Agrega el diente de ajo picado y cocina por un minuto más, evitando que se queme.","Incorpora el jamón serrano en dados a la sartén y sofríe durante unos 3-4 minutos, hasta que comience a dorarse.","Añade los guisantes a la mezcla y revuelve bien. Cocina durante 5-7 minutos si son frescos, o 3-4 minutos si son congelados.","Sazona con pimienta negra al gusto y mezcla bien todos los ingredientes.","Retira del fuego y sirve caliente, decorado con perejil fresco picado si lo deseas."]'::jsonb, 'Disfruta de esta deliciosa y reconfortante receta de guisantes con jamón, perfecta para una cena nutritiva que alegrará tu paladar y te hará sentir satisfecho.', '["Para un sabor más intenso, puedes añadir un toque de caldo de pollo o verduras al cocinar los guisantes.","Si prefieres un plato más cremoso, considera añadir una cucharada de nata o yogur natural al final de la cocción.","Utiliza guisantes frescos de temporada para un sabor más dulce y fresco."]'::jsonb, '["Sustituye el jamón serrano por pechuga de pavo para una opción más magra.","Puedes usar guisantes congelados si no tienes frescos a mano.","Reemplaza el aceite de oliva por aceite de aguacate para un perfil de grasa diferente."]'::jsonb, '["Los guisantes son ricos en fibra, lo que ayuda a la digestión y a mantener la sensación de saciedad.","El jamón serrano aporta proteínas de alta calidad que son esenciales para la reparación muscular.","Ambos ingredientes son fuentes de vitaminas y minerales, como la vitamina C y el hierro."]'::jsonb, '["La alta cantidad de fibra en los guisantes ayuda a controlar el apetito y a reducir la ingesta calórica total.","La combinación de proteínas y fibra favorece la saciedad, lo que puede evitar picoteos innecesarios.","Es un plato bajo en calorías pero lleno de sabor, lo que facilita mantener una alimentación equilibrada."]'::jsonb),
(gen_random_uuid(), 'Cazuela de sepia y gambas', 'Cena', '/images/r_cena_18.png', 250, 35, 5, 8, 20, '{"Principal":["300g de sepia limpia y cortada en trozos","200g de gambas peladas","1 cebolla mediana picada","2 dientes de ajo picados","1 pimiento rojo picado","200g de tomate triturado","150ml de caldo de pescado","1 cucharadita de pimentón dulce","2 cucharadas de aceite de oliva","Sal y pimienta al gusto"],"Opcional":["Perejil fresco picado para decorar","1 hoja de laurel","Pimienta roja para dar un toque picante"]}'::jsonb, '["En una cazuela grande, calienta el aceite de oliva a fuego medio y añade la cebolla picada. Sofríe hasta que esté transparente.","Agrega los ajos picados y el pimiento rojo, y cocina por unos minutos hasta que estén tiernos.","Incorpora la sepia y cocina durante unos 5 minutos, removiendo ocasionalmente, hasta que esté ligeramente dorada.","Añade el tomate triturado, el pimentón dulce y la hoja de laurel, mezclando bien todos los ingredientes.","Vierte el caldo de pescado y lleva a ebullición. Reduce el fuego y deja que se cocine a fuego lento durante 15 minutos.","Finalmente, agrega las gambas peladas y cocina por 5 minutos más, hasta que estén rosadas y tiernas. Rectifica la sal y la pimienta al gusto."]'::jsonb, 'Disfruta de una deliciosa cazuela de sepia y gambas, una explosión de sabores del mar que no solo deleitará tu paladar, sino que también nutrirá tu cuerpo con ingredientes frescos y saludables.', '["Para potenciar el sabor, utiliza gambas frescas en lugar de congeladas.","Asegúrate de no sobrecocinar las gambas para que mantengan su textura jugosa.","Puedes añadir un chorrito de vino blanco al sofrito para darle un toque adicional de sabor."]'::jsonb, '["Sustituye la sepia por calamares si prefieres un sabor diferente.","Utiliza caldo de verduras en lugar de caldo de pescado para una versión vegetariana.","Reemplaza el pimiento rojo por pimientos amarillos o verdes según tu preferencia."]'::jsonb, '["La sepia es rica en proteínas y baja en grasas, ideal para mantener una dieta equilibrada.","Las gambas aportan ácidos grasos omega-3, beneficiosos para la salud cardiovascular.","Los vegetales como cebolla y pimiento aportan fibra y antioxidantes esenciales."]'::jsonb, '["Bajo en calorías y alto en proteínas, este plato ayuda a sentirse saciado por más tiempo.","La fibra de los vegetales contribuye a una mejor digestión y control del apetito.","Las proteínas magras ayudan a mantener la masa muscular durante la pérdida de peso."]'::jsonb),
(gen_random_uuid(), 'Champiñones rellenos de pavo', 'Cena', '/images/r_cena_19.png', 210, 20, 8, 10, 25, '{"Principal":["500g de champiñones grandes","300g de pavo molido","1 cebolla pequeña, picada","2 dientes de ajo, picados","100g de espinacas frescas","100g de queso ricotta","1 cucharada de aceite de oliva","Sal y pimienta al gusto","Perejil fresco picado para decorar"],"Opcional":["50g de queso parmesano rallado","Pimientos rojos asados, picados","Nueces picadas para un toque crujiente"]}'::jsonb, '["Precalienta el horno a 180°C (350°F).","Limpia los champiñones con un paño húmedo y quita los tallos, reservándolos para el relleno.","En una sartén grande, calienta el aceite de oliva a fuego medio y añade la cebolla y el ajo picados, cocinando hasta que estén dorados.","Agrega el pavo molido a la sartén y cocina hasta que esté bien dorado, desmenuzándolo con una cuchara de madera.","Incorpora los tallos de champiñón picados y las espinacas, cocinando hasta que las espinacas se marchiten. Añade sal y pimienta al gusto.","Retira del fuego y mezcla con el queso ricotta. Rellena cada champiñón con esta mezcla y colócalos en una bandeja para hornear.","Si deseas, espolvorea queso parmesano por encima y hornea durante 20-25 minutos, o hasta que los champiñones estén tiernos y el relleno burbujeante."]'::jsonb, 'Disfruta de unos sabrosos champiñones rellenos de pavo, una cena ligera y nutritiva que deleitará tu paladar mientras cuidas de tu bienestar. Perfectos para una noche de confort saludable.', '["Asegúrate de no cocinar demasiado los champiñones antes de hornearlos para que no se vuelvan gomosos.","Si prefieres un sabor más intenso, añade especias como comino o pimentón al relleno.","Utiliza champiñones de tamaño uniforme para que se cocinen de manera homogénea."]'::jsonb, '["Reemplaza el pavo molido por pollo molido o tofu si buscas una opción vegetariana.","Usa queso cottage en lugar de ricotta para reducir las calorías y aumentar la proteína.","Sustituye las espinacas por kale o acelgas para variar los nutrientes."]'::jsonb, '["El pavo es una excelente fuente de proteína magra, ideal para la construcción muscular.","Los champiñones son bajos en calorías y ricos en antioxidantes, apoyando la salud general.","Las espinacas aportan hierro y vitaminas A y C, contribuyendo a una dieta equilibrada."]'::jsonb, '["Este plato es bajo en calorías, lo que permite disfrutar de una cena satisfactoria sin excesos.","La alta proteína del pavo ayuda a mantener la saciedad, reduciendo el deseo de picar entre comidas.","Las verduras aportan fibra, que favorece la digestión y la sensación de plenitud."]'::jsonb),
(gen_random_uuid(), 'Ensalada tibia de judías verdes', 'Cena', '/images/r_cena_20.png', 240, 12, 15, 14, 15, '{"Principal":["300 g de judías verdes frescas","200 g de tomates cherry","100 g de queso feta desmenuzado","50 g de nueces troceadas","2 cucharadas de aceite de oliva","1 cucharada de vinagre balsámico","Sal y pimienta al gusto"],"Opcional":["1 diente de ajo picado","Albahaca fresca para decorar"]}'::jsonb, '["Lava y corta las judías verdes en trozos de aproximadamente 5 cm.","En una olla con agua hirviendo y sal, blanquea las judías verdes durante 3-4 minutos hasta que estén tiernas pero crujientes.","Escurre las judías verdes y sumérgelas en agua fría para detener la cocción y mantener su color vibrante.","En una sartén grande, calienta el aceite de oliva a fuego medio y añade el ajo picado, cocinando por 1 minuto.","Agrega las judías verdes y los tomates cherry cortados por la mitad a la sartén, y saltea durante 2-3 minutos.","Retira del fuego, añade el queso feta, las nueces y el vinagre balsámico, y mezcla bien. Sazona con sal y pimienta al gusto antes de servir."]'::jsonb, 'Disfruta de una deliciosa ensalada tibia de judías verdes que combina frescura y sabor en cada bocado, perfecta para una cena nutritiva y reconfortante.', '["Para un sabor extra, tuesta las nueces ligeramente en la sartén antes de añadirlas a la ensalada.","Utiliza judías verdes frescas para obtener la mejor textura y sabor, evitando las enlatadas.","Prueba añadir un poco de limón rallado para un toque cítrico y fresco."]'::jsonb, '["Sustituye el queso feta por queso de cabra o tofu para una opción vegana.","Cambia las nueces por almendras o semillas de girasol según tus preferencias.","Usa espinacas frescas en lugar de judías verdes para una ensalada diferente."]'::jsonb, '["Las judías verdes son ricas en fibra, lo que promueve la salud digestiva.","El queso feta aporta calcio y proteínas, esenciales para la salud ósea.","Las nueces son una fuente de grasas saludables que benefician el corazón."]'::jsonb, '["Bajo en calorías y alto en fibra, lo que ayuda a mantener la saciedad.","Los ingredientes frescos y naturales promueven un metabolismo saludable.","El consumo de ensaladas ricas en vegetales puede reducir el deseo de alimentos poco saludables."]'::jsonb),
(gen_random_uuid(), 'Sopa de miso con tofu', 'Cena', '/images/r_cena_21.png', 160, 12, 10, 6, 10, '{"Principal":["4 tazas de agua","3 cucharadas de pasta de miso","200 g de tofu firme, cortado en cubos","1 taza de algas wakame rehidratadas","1/2 taza de cebolla verde, picada","1 taza de champiñones, en rodajas"],"Opcional":["Semillas de sésamo tostadas para decorar","Rodajas de chile rojo para un toque picante"]}'::jsonb, '["En una olla grande, lleva el agua a ebullición a fuego medio-alto.","Reduce el fuego y añade la pasta de miso, mezclando bien hasta que se disuelva completamente.","Incorpora los champiñones y cocina a fuego lento durante unos 5 minutos, hasta que estén tiernos.","Añade el tofu en cubos y las algas wakame, cocinando por otros 3-4 minutos.","Retira la sopa del fuego y mezcla la cebolla verde picada justo antes de servir.","Sirve caliente, decorando con semillas de sésamo y rodajas de chile rojo si lo deseas."]'::jsonb, 'Disfruta de una reconfortante sopa de miso con tofu, un plato lleno de umami que nutre tanto el cuerpo como el alma. Este delicioso caldo es perfecto para relajarte al final del día.', '["No hiervas la sopa después de añadir la pasta de miso, ya que esto puede afectar su sabor y propiedades beneficiosas.","Puedes usar un batidor para disolver la pasta de miso más fácilmente, asegurando una textura suave.","Ajusta la cantidad de miso según tu preferencia personal; prueba la sopa y ajusta al gusto."]'::jsonb, '["Puedes reemplazar el tofu firme por tempeh para un perfil de sabor diferente y mayor contenido proteico.","Si no tienes algas wakame, puedes usar espinacas frescas como alternativa.","La pasta de miso puede ser sustituida por caldo de verduras para una versión más ligera."]'::jsonb, '["El miso es una excelente fuente de probióticos que ayudan a la salud digestiva.","El tofu aporta proteínas vegetales de alta calidad y es bajo en calorías.","Las algas wakame son ricas en minerales como yodo, que son esenciales para la salud tiroidea."]'::jsonb, '["La sopa es baja en calorías, lo que permite disfrutar de una cena satisfactoria sin exceder el límite calórico.","Su contenido en proteínas y fibra puede ayudar a aumentar la saciedad y reducir el hambre.","Los ingredientes como el miso y el tofu pueden ayudar a estabilizar los niveles de azúcar en sangre, lo que es clave para el control del peso."]'::jsonb);
